import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { Dashboard } from './components/Dashboard';
import { ClassManager } from './components/ClassManager';
import { StudentManager } from './components/StudentManager';
import { GradingSheet } from './components/GradingSheet';
import { AttendanceSheet } from './components/AttendanceSheet';
import { JournalManager } from './components/JournalManager';
import { AITools } from './components/AITools';
import { Login } from './components/Login';
import { ViewState } from './types';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.LOGIN);
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(false);

  // Simulate checking session on mount
  useEffect(() => {
    const session = localStorage.getItem('ar_app_session');
    if (session === 'active') {
      setIsAuthenticated(true);
      setCurrentView(ViewState.DASHBOARD);
    }
  }, []);

  const handleLogin = () => {
    localStorage.setItem('ar_app_session', 'active');
    setIsAuthenticated(true);
    setCurrentView(ViewState.DASHBOARD);
  };

  const handleLogout = () => {
    localStorage.removeItem('ar_app_session');
    setIsAuthenticated(false);
    setCurrentView(ViewState.LOGIN);
  };

  if (!isAuthenticated) {
    return <Login onLogin={handleLogin} />;
  }

  const renderContent = () => {
    switch (currentView) {
      case ViewState.DASHBOARD:
        return <Dashboard />;
      case ViewState.CLASSES:
        return <ClassManager />;
      case ViewState.STUDENTS:
        return <StudentManager />;
      case ViewState.GRADING:
        return <GradingSheet />;
      case ViewState.ATTENDANCE:
        return <AttendanceSheet />;
      case ViewState.JOURNAL:
        return <JournalManager />;
      case ViewState.AI_TOOLS:
        return <AITools />;
      default:
        return <Dashboard />;
    }
  };

  return (
    <Layout currentView={currentView} onViewChange={setCurrentView} onLogout={handleLogout}>
      {renderContent()}
    </Layout>
  );
};

export default App;

export enum ViewState {
  LOGIN = 'LOGIN',
  DASHBOARD = 'DASHBOARD',
  CLASSES = 'CLASSES',
  STUDENTS = 'STUDENTS',
  GRADING = 'GRADING',
  ATTENDANCE = 'ATTENDANCE',
  JOURNAL = 'JOURNAL',
  AI_TOOLS = 'AI_TOOLS'
}

export enum Gender {
  L = 'L',
  P = 'P'
}

export interface Classroom {
  id: string;
  name: string;
  semester: string;
  academicYear: string;
}

export interface Student {
  id: string;
  nisn: string;
