import { Student, Classroom, GradeData, AttendanceData, JournalEntry, Gender } from '../types';
import { MOCK_CLASSES } from '../constants';

// Keys
const KEYS = {
  CLASSES: 'ar_classes',
  STUDENTS: 'ar_students',
  GRADES: 'ar_grades',
  ATTENDANCE: 'ar_attendance',
  JOURNAL: 'ar_journal'
};

// Helpers
const get = <T,>(key: string, defaultVal: T): T => {
  const data = localStorage.getItem(key);
  return data ? JSON.parse(data) : defaultVal;
};

const set = <T,>(key: string, data: T) => {
  localStorage.setItem(key, JSON.stringify(data));
};

// Initial Seeder
export const seedDatabase = () => {
  if (!localStorage.getItem(KEYS.CLASSES)) {
    set(KEYS.CLASSES, MOCK_CLASSES);
    // Seed some students
    const students: Student[] = [
      { id: 's1', nisn: '1234567890', name: 'Ahmad Dahlan', gender: Gender.L, classId: 'c1' },
      { id: 's2', nisn: '0987654321', name: 'Siti Aminah', gender: Gender.P, classId: 'c1' },
    ];
    set(KEYS.STUDENTS, students);
  }
};

// Classes
export const getClasses = (): Classroom[] => get(KEYS.CLASSES, []);
export const saveClass = (cls: Classroom) => {
  const classes = getClasses();
  const idx = classes.findIndex(c => c.id === cls.id);
  if (idx >= 0) classes[idx] = cls;
  else classes.push(cls);
  set(KEYS.CLASSES, classes);
};
export const deleteClass = (id: string) => {
  const classes = getClasses().filter(c => c.id !== id);
  set(KEYS.CLASSES, classes);
  // Cascade delete logic would go here (delete students of this class)
  const students = getStudents().filter(s => s.classId !== id);
  set(KEYS.STUDENTS, students);
};

// Students
export const getStudents = (): Student[] => get(KEYS.STUDENTS, []);
export const getStudentsByClass = (classId: string): Student[] => getStudents().filter(s => s.classId === classId);
export const saveStudent = (student: Student) => {
  const students = getStudents();
  const idx = students.findIndex(s => s.id === student.id);
  if (idx >= 0) students[idx] = student;
  else students.push(student);
  set(KEYS.STUDENTS, students);
};
export const deleteStudent = (id: string) => {
  set(KEYS.STUDENTS, getStudents().filter(s => s.id !== id));
};

// Grades
export const getGrades = (): GradeData[] => get(KEYS.GRADES, []);
export const getGradeByStudent = (studentId: string): GradeData => {
  const grades = getGrades();
  const found = grades.find(g => g.studentId === studentId);
  if (found) return found;
  return {
    studentId,
    classId: '',
    formatif: Array(8).fill(0),
    sumatif: Array(5).fill(0),
    sasNonTes: 0,
    sasTes: 0
  };
};
export const saveGrade = (grade: GradeData) => {
  const grades = getGrades();
  const idx = grades.findIndex(g => g.studentId === grade.studentId);
  if (idx >= 0) grades[idx] = grade;
  else grades.push(grade);
  set(KEYS.GRADES, grades);
};

// Attendance
export const getAttendance = (): AttendanceData[] => get(KEYS.ATTENDANCE, []);
export const getAttendanceByStudent = (studentId: string): AttendanceData => {
  const list = getAttendance();
  const found = list.find(a => a.studentId === studentId);
  if (found) return found;
  return { studentId, classId: '', meetings: Array(20).fill('') };
};
export const saveAttendance = (data: AttendanceData) => {
  const list = getAttendance();
  const idx = list.findIndex(a => a.studentId === data.studentId);
  if (idx >= 0) list[idx] = data;
  else list.push(data);
  set(KEYS.ATTENDANCE, list);
};

// Journal
export const getJournals = (): JournalEntry[] => get(KEYS.JOURNAL, []);
export const saveJournal = (entry: JournalEntry) => {
  const list = getJournals();
  const idx = list.findIndex(j => j.id === entry.id);
  if (idx >= 0) list[idx] = entry;
  else list.push(entry);
  set(KEYS.JOURNAL, list);
};

seedDatabase();

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

const getAIClient = () => {
    // Note: In a real app, API key should come from env. 
    // Here we assume process.env.API_KEY is available as per instructions.
    if (!process.env.API_KEY) {
        throw new Error("API Key missing");
    }
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

export const editImageWithGemini = async (base64Image: string, prompt: string, mimeType: string): Promise<string> => {
    const ai = getAIClient();
    try {
        const response: GenerateContentResponse = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: {
                parts: [
                    {
                        inlineData: {
                            mimeType: mimeType,
                            data: base64Image
                        }
                    },
                    {
                        text: prompt
                    }
                ]
            }
        });

        // Parse response for image
        if (response.candidates && response.candidates[0].content && response.candidates[0].content.parts) {
            for (const part of response.candidates[0].content.parts) {
                if (part.inlineData && part.inlineData.data) {
                    return `data:${part.inlineData.mimeType || 'image/png'};base64,${part.inlineData.data}`;
                }
            }
        }
        throw new Error("No image generated");
    } catch (error) {
        console.error("Gemini Image Edit Error", error);
        throw error;
    }
};

export interface SearchResult {
    text: string;
    links: { title: string; uri: string }[];
}

export const searchTeachingResources = async (query: string): Promise<SearchResult> => {
    const ai = getAIClient();
    try {
        const response: GenerateContentResponse = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: `Search for this topic related to Arabic teaching: ${query}. Provide a summary and list relevant resources.`,
            config: {
                tools: [{ googleSearch: {} }],
            },
        });

        const text = response.text || "No results found.";

        const links: { title: string; uri: string }[] = [];
        const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

        if (chunks) {
            chunks.forEach((chunk: any) => {
                if (chunk.web) {
                    links.push({ title: chunk.web.title, uri: chunk.web.uri });
                }
            });
        }

        return { text, links };
    } catch (error) {
        console.error("Gemini Search Error", error);
        throw error;
    }
};

