import React, { useEffect, useState } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';
import { getClasses, getStudents, getGrades } from '../services/storageService';
import { KKM, WEIGHTS } from '../constants';
import { Student, GradeData } from '../types';

export const Dashboard: React.FC = () => {
  const [stats, setStats] = useState({
    totalClasses: 0,
    totalStudents: 0,
    passRate: 0,
    averageScore: 0
  });
  const [chartData, setChartData] = useState<any[]>([]);

  useEffect(() => {
    const classes = getClasses();
    const students = getStudents();
    const grades = getGrades();

    let totalScore = 0;
    let passedCount = 0;
    let gradedCount = 0;

    // Calculate pass/fail per class for chart
    const classStats = classes.map(cls => {
      const clsStudents = students.filter(s => s.classId === cls.id);
      let clsPassed = 0;
      let clsAvg = 0;
      let clsGraded = 0;

      clsStudents.forEach(student => {
        const grade = grades.find(g => g.studentId === student.id);
        if (grade) {
          const avgF = grade.formatif.reduce((a, b) => a + b, 0) / (grade.formatif.filter(n => n > 0).length || 1);
          const avgS = grade.sumatif.reduce((a, b) => a + b, 0) / (grade.sumatif.filter(n => n > 0).length || 1);
          const sas = (grade.sasNonTes + grade.sasTes) / 2;
          const final = (avgF * WEIGHTS.FORMATIF) + (avgS * WEIGHTS.SUMATIF) + (sas * WEIGHTS.SAS);

          if (final > 0) {
            totalScore += final;
            clsAvg += final;
            gradedCount++;
            clsGraded++;
            if (final >= KKM) {
              passedCount++;
              clsPassed++;
            }
          }
        }
      });

      return {
        name: cls.name,
        Tuntas: clsPassed,
        Belum: clsStudents.length - clsPassed, // Simplified assumption
        avg: clsGraded > 0 ? (clsAvg / clsGraded).toFixed(1) : 0
      };
    });

    setStats({
      totalClasses: classes.length,
      totalStudents: students.length,
      passRate: gradedCount > 0 ? Math.round((passedCount / gradedCount) * 100) : 0,
      averageScore: gradedCount > 0 ? Math.round(totalScore / gradedCount) : 0
    });

    setChartData(classStats);
  }, []);

  return (
    <div className="space-y-6">
      <h2 className="text-2xl font-bold text-gray-800 border-b pb-2 border-gray-200">
        Assalamu'alaikum, Selamat Datang di Dashboard
      </h2>

      {/* Stat Cards */}
      <div className="grid grid-cols-1 gap-5 sm:grid-cols-2 lg:grid-cols-4">
        {[
          { label: 'Total Kelas', value: stats.totalClasses, color: 'bg-blue-500', icon: '🏫' },
          { label: 'Total Siswa', value: stats.totalStudents, color: 'bg-islamic-500', icon: '👨‍🎓' },
          { label: 'Rata-rata Nilai', value: stats.averageScore, color: 'bg-yellow-500', icon: '📈' },
          { label: 'Ketuntasan', value: `${stats.passRate}%`, color: 'bg-indigo-500', icon: '✅' },
        ].map((stat, i) => (
          <div key={i} className="bg-white overflow-hidden shadow rounded-lg flex items-center p-5 border-l-4 border-islamic-600">
            <div className={`flex-shrink-0 p-3 rounded-md ${stat.color} bg-opacity-10`}>
              <span className="text-2xl">{stat.icon}</span>
            </div>
            <div className="ml-5 w-0 flex-1">
              <dt className="text-sm font-medium text-gray-500 truncate">{stat.label}</dt>
              <dd className="text-lg font-bold text-gray-900">{stat.value}</dd>
            </div>
          </div>
        ))}
      </div>

      {/* Chart */}
      <div className="bg-white shadow rounded-lg p-6">
        <h3 className="text-lg font-medium leading-6 text-gray-900 mb-4">Statistik Ketuntasan Per Kelas</h3>
        <div className="h-80 w-full">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={chartData}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="name" />
              <YAxis />
              <Tooltip />
              <Legend />
              <Bar dataKey="Tuntas" stackId="a" fill="#16a34a" />
              <Bar dataKey="Belum" stackId="a" fill="#ef4444" />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      <div className="bg-white shadow rounded-lg p-6">
         <h3 className="text-lg font-medium leading-6 text-gray-900 mb-2">Informasi Sistem</h3>
         <ul className="list-disc list-inside text-gray-600 space-y-1">
            <li>KKM (Kriteria Ketuntasan Minimal): <strong>{KKM}</strong></li>
            <li>Bobot Nilai: Formatif ({WEIGHTS.FORMATIF * 100}%), Sumatif ({WEIGHTS.SUMATIF * 100}%), SAS ({WEIGHTS.SAS * 100}%)</li>
            <li>Kurikulum: <strong>Merdeka</strong></li>
         </ul>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Classroom } from '../types';
import { getClasses, saveClass, deleteClass } from '../services/storageService';

export const ClassManager: React.FC = () => {
  const [classes, setClasses] = useState<Classroom[]>([]);
  const [editing, setEditing] = useState<Classroom | null>(null);
  const [form, setForm] = useState<Partial<Classroom>>({ name: '', semester: 'Ganjil', academicYear: '' });

  useEffect(() => {
    refresh();
  }, []);

  const refresh = () => setClasses(getClasses());

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.name || !form.academicYear) return;

    const newClass: Classroom = {
      id: editing ? editing.id : Date.now().toString(),
      name: form.name,
      semester: form.semester || 'Ganjil',
      academicYear: form.academicYear,
    };

    saveClass(newClass);
    setForm({ name: '', semester: 'Ganjil', academicYear: '' });
    setEditing(null);
    refresh();
  };

  const handleEdit = (cls: Classroom) => {
    setEditing(cls);
    setForm(cls);
  };

  const handleDelete = (id: string) => {
    if (confirm('Yakin ingin menghapus kelas ini? Data siswa dan nilai terkait akan hilang.')) {
      deleteClass(id);
      refresh();
    }
  };

  return (
    <div className="space-y-6">
      <h2 className="text-2xl font-bold text-gray-800">Kelola Data Kelas</h2>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {/* Form */}
        <div className="md:col-span-1 bg-white p-6 rounded-lg shadow h-fit">
          <h3 className="text-lg font-medium mb-4">{editing ? 'Edit Kelas' : 'Tambah Kelas Baru'}</h3>
          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700">Nama Kelas</label>
              <input
                type="text"
                className="mt-1 block w-full rounded-md border-gray-300 shadow-sm border p-2 focus:border-islamic-500 focus:ring-islamic-500"
                placeholder="Contoh: 7-A"
                value={form.name}
                onChange={e => setForm({ ...form, name: e.target.value })}
                required
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700">Semester</label>
              <select
                className="mt-1 block w-full rounded-md border-gray-300 shadow-sm border p-2"
                value={form.semester}
                onChange={e => setForm({ ...form, semester: e.target.value })}
              >
                <option value="Ganjil">Ganjil</option>
                <option value="Genap">Genap</option>
              </select>
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700">Tahun Pelajaran</label>
              <input
                type="text"
                className="mt-1 block w-full rounded-md border-gray-300 shadow-sm border p-2"
                placeholder="2024/2025"
                value={form.academicYear}
                onChange={e => setForm({ ...form, academicYear: e.target.value })}
                required
              />
            </div>
            <div className="flex space-x-2">
