import React, { useState, useEffect, useMemo } from 'react';
import { Student, GradeData, Classroom } from '../types';
import { getClasses, getStudentsByClass, getGradeByStudent, saveGrade } from '../services/storageService';
import { KKM, WEIGHTS } from '../constants';

export const GradingSheet: React.FC = () => {
  const [selectedClass, setSelectedClass] = useState<string>('');
  const [classes, setClasses] = useState<Classroom[]>([]);
  const [students, setStudents] = useState<Student[]>([]);
  const [grades, setGrades] = useState<Record<string, GradeData>>({});

  useEffect(() => {
    setClasses(getClasses());
  }, []);

  useEffect(() => {
    if (selectedClass) {
      const clsStudents = getStudentsByClass(selectedClass);
      setStudents(clsStudents);
      const gradeMap: Record<string, GradeData> = {};
      clsStudents.forEach(s => {
        gradeMap[s.id] = getGradeByStudent(s.id);
      });
      setGrades(gradeMap);
    }
  }, [selectedClass]);

  const handleGradeChange = (studentId: string, field: 'formatif' | 'sumatif', index: number, value: string) => {
    const numVal = parseFloat(value) || 0;
    const currentGrade = { ...grades[studentId] };
    if (field === 'formatif') {
      const newF = [...currentGrade.formatif];
      newF[index] = numVal;
      currentGrade.formatif = newF;
    } else {
      const newS = [...currentGrade.sumatif];
      newS[index] = numVal;
      currentGrade.sumatif = newS;
    }
    setGrades(prev => ({ ...prev, [studentId]: currentGrade }));
    saveGrade(currentGrade);
  };

  const handleSasChange = (studentId: string, field: 'sasNonTes' | 'sasTes', value: string) => {
    const numVal = parseFloat(value) || 0;
    const currentGrade = { ...grades[studentId], [field]: numVal };
    setGrades(prev => ({ ...prev, [studentId]: currentGrade }));
    saveGrade(currentGrade);
  };

  // Automated Calculations
  const calculatedData = useMemo(() => {
    return students.map(s => {
      const g = grades[s.id];
      if (!g) return null;

      const validF = g.formatif.filter(n => n > 0);
      const avgF = validF.length > 0 ? validF.reduce((a, b) => a + b, 0) / validF.length : 0;

      const validS = g.sumatif.filter(n => n > 0);
      const avgS = validS.length > 0 ? validS.reduce((a, b) => a + b, 0) / validS.length : 0;

      const sas = (g.sasNonTes + g.sasTes) / 2;

      const final = (avgF * WEIGHTS.FORMATIF) + (avgS * WEIGHTS.SUMATIF) + (sas * WEIGHTS.SAS);
      const isPassing = final >= KKM;

      return {
        ...s,
        avgF,
        avgS,
        sas,
        final,
        isPassing
      };
    }).sort((a, b) => (b?.final || 0) - (a?.final || 0)); // Rank by final grade
  }, [students, grades]);

  // Stats
  const stats = useMemo(() => {
    if (!calculatedData.length) return null;
    const scores = calculatedData.map(d => d?.final || 0).filter(s => s > 0);
    if (!scores.length) return null;
    return {
      max: Math.max(...scores),
      min: Math.min(...scores),
      avg: scores.reduce((a,b) => a+b,0) / scores.length,
      tuntas: calculatedData.filter(d => d && d.isPassing).length,
      belum: calculatedData.filter(d => d && !d.isPassing).length,
    };
  }, [calculatedData]);

  if (!classes.length) return <div className="p-4">Belum ada kelas. Silakan tambah kelas dulu.</div>;

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-gray-800">Rekap Nilai Kurikulum Merdeka</h2>
        <select 
          className="border p-2 rounded shadow-sm"
          value={selectedClass}
          onChange={(e) => setSelectedClass(e.target.value)}
        >
          <option value="">-- Pilih Kelas --</option>
          {classes.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
        </select>
      </div>

      {selectedClass && stats && (
        <div className="grid grid-cols-5 gap-4 bg-white p-4 rounded shadow">
           <div className="text-center"><div className="text-xs text-gray-500">Tertinggi</div><div className="font-bold text-green-600">{stats.max.toFixed(1)}</div></div>
           <div className="text-center"><div className="text-xs text-gray-500">Terendah</div><div className="font-bold text-red-600">{stats.min.toFixed(1)}</div></div>
           <div className="text-center"><div className="text-xs text-gray-500">Rata-rata</div><div className="font-bold text-blue-600">{stats.avg.toFixed(1)}</div></div>
           <div className="text-center"><div className="text-xs text-gray-500">Tuntas</div><div className="font-bold text-islamic-600">{stats.tuntas}</div></div>
           <div className="text-center"><div className="text-xs text-gray-500">Belum</div><div className="font-bold text-red-500">{stats.belum}</div></div>
        </div>
      )}

      {selectedClass && (
        <div className="bg-white rounded-lg shadow overflow-hidden flex flex-col">
          <div className="overflow-x-auto">
            <table className="min-w-max divide-y divide-gray-200 border-collapse">
              <thead className="bg-islamic-700 text-white">
                <tr>
                  <th rowSpan={2} className="px-4 py-2 text-left text-xs uppercase sticky left-0 bg-islamic-700 z-10">Ranking</th>
                  <th rowSpan={2} className="px-4 py-2 text-left text-xs uppercase sticky left-16 bg-islamic-700 z-10 w-48">Nama Siswa</th>
                  <th colSpan={9} className="px-2 py-1 text-center text-xs border-l border-islamic-600">Formatif (40%)</th>
                  <th colSpan={6} className="px-2 py-1 text-center text-xs border-l border-islamic-600">Sumatif (30%)</th>
                  <th colSpan={3} className="px-2 py-1 text-center text-xs border-l border-islamic-600">SAS (30%)</th>
                  <th rowSpan={2} className="px-4 py-2 text-center text-xs uppercase border-l border-islamic-600 w-24">Nilai Akhir</th>
                  <th rowSpan={2} className="px-4 py-2 text-center text-xs uppercase w-24">Ket.</th>
                </tr>
                <tr>
                  {/* F1-F8 + Avg */}
                  {[1,2,3,4,5,6,7,8].map(i => <th key={`fh-${i}`} className="px-1 py-1 w-10 border-t border-l border-islamic-600 text-xs text-center">F{i}</th>)}
                  <th className="px-1 py-1 w-12 border-t border-l border-islamic-600 bg-islamic-800 text-xs">Rata</th>

                  {/* S1-S5 + Avg */}
                  {[1,2,3,4,5].map(i => <th key={`sh-${i}`} className="px-1 py-1 w-10 border-t border-l border-islamic-600 text-xs text-center">S{i}</th>)}
                   <th className="px-1 py-1 w-12 border-t border-l border-islamic-600 bg-islamic-800 text-xs">Rata</th>

                  {/* SAS */}
                  <th className="px-1 py-1 w-12 border-t border-l border-islamic-600 text-xs">Non</th>
                  <th className="px-1 py-1 w-12 border-t border-l border-islamic-600 text-xs">Tes</th>
                  <th className="px-1 py-1 w-12 border-t border-l border-islamic-600 bg-islamic-800 text-xs">NA</th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {calculatedData.map((s, idx) => {
                  if (!s) return null;
                  const g = grades[s.id];
                  return (
                    <tr key={s.id} className="hover:bg-gray-50">
                      <td className="px-4 py-2 text-sm text-center sticky left-0 bg-white z-0 font-bold">{idx + 1}</td>
                      <td className="px-4 py-2 text-sm font-medium sticky left-16 bg-white z-0">{s.name}</td>

                      {/* Formatif Inputs */}
                      {g.formatif.map((val, i) => (
                        <td key={`f-${i}`} className="p-1 border-l">
                          <input type="text" className="w-8 text-center text-xs border-none focus:ring-0 p-0" 
                             value={val || ''} 
                             onChange={(e) => handleGradeChange(s.id, 'formatif', i, e.target.value)} 
                          />
                        </td>
                      ))}
                      <td className="px-2 py-1 text-center font-bold text-xs bg-gray-100 border-l">{s.avgF.toFixed(0)}</td>

                      {/* Sumatif Inputs */}
                      {g.sumatif.map((val, i) => (
                        <td key={`s-${i}`} className="p-1 border-l">
                          <input type="text" className="w-8 text-center text-xs border-none focus:ring-0 p-0" 
                             value={val || ''} 
                             onChange={(e) => handleGradeChange(s.id, 'sumatif', i, e.target.value)} 
                          />
                        </td>
                      ))}
                      <td className="px-2 py-1 text-center font-bold text-xs bg-gray-100 border-l">{s.avgS.toFixed(0)}</td>

                      {/* SAS Inputs */}
                      <td className="p-1 border-l">
                         <input type="text" className="w-10 text-center text-xs border-none focus:ring-0 p-0" 
                             value={g.sasNonTes || ''} 
                             onChange={(e) => handleSasChange(s.id, 'sasNonTes', e.target.value)} 
                          />
                      </td>
                      <td className="p-1 border-l">
                         <input type="text" className="w-10 text-center text-xs border-none focus:ring-0 p-0" 
                             value={g.sasTes || ''} 
                             onChange={(e) => handleSasChange(s.id, 'sasTes', e.target.value)} 
                          />
                      </td>
                      <td className="px-2 py-1 text-center font-bold text-xs bg-gray-100 border-l">{s.sas.toFixed(0)}</td>

                      {/* Final */}
                      <td className="px-4 py-2 text-center font-bold text-sm border-l">{s.final.toFixed(0)}</td>
                      <td className={`px-4 py-2 text-center text-xs font-bold text-white ${s.isPassing ? 'bg-green-500' : 'bg-red-500'}`}>
                        {s.isPassing ? 'Tuntas' : 'Belum'}
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
};

