                            ${att.meetings[i] === 'H' ? 'bg-green-50 text-green-600' : ''}
                           `}
                           value={att.meetings[i] || ''}
                           onChange={(e) => handleStatusChange(s.id, i, e.target.value)}
                         >
                           <option value=""></option>
                           {ATTENDANCE_OPTIONS.map(opt => <option key={opt} value={opt}>{opt}</option>)}
                         </select>
                      </td>
                    ))}
                    <td className="text-center font-bold border-l">{countStatus(att.meetings, 'H')}</td>
                    <td className="text-center">{countStatus(att.meetings, 'I')}</td>
                    <td className="text-center">{countStatus(att.meetings, 'S')}</td>
                    <td className="text-center text-red-600 font-bold">{countStatus(att.meetings, 'A')}</td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { JournalEntry, Classroom } from '../types';
import { getClasses, getJournals, saveJournal } from '../services/storageService';
import { SCHOOL_NAME } from '../constants';

export const JournalManager: React.FC = () => {
  const [entries, setEntries] = useState<JournalEntry[]>([]);
  const [classes, setClasses] = useState<Classroom[]>([]);
  const [showForm, setShowForm] = useState(false);
  const [form, setForm] = useState<Partial<JournalEntry>>({
    date: new Date().toISOString().split('T')[0],
    attendanceSummary: { hadir: 0, izin: 0, sakit: 0, alfa: 0 }
  });

  useEffect(() => {
    setClasses(getClasses());
    setEntries(getJournals().sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
  }, []);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.topic || !form.classId) return;

    const entry: JournalEntry = {
      id: Date.now().toString(),
      date: form.date!,
      classId: form.classId!,
      topic: form.topic!,
      activity: form.activity || '',
      notes: form.notes || '',
      attendanceSummary: {
        hadir: Number(form.attendanceSummary?.hadir) || 0,
        izin: Number(form.attendanceSummary?.izin) || 0,
        sakit: Number(form.attendanceSummary?.sakit) || 0,
        alfa: Number(form.attendanceSummary?.alfa) || 0,
      }
    };

    saveJournal(entry);
    setEntries([entry, ...entries]);
    setShowForm(false);
    setForm({ date: new Date().toISOString().split('T')[0], attendanceSummary: { hadir: 0, izin: 0, sakit: 0, alfa: 0 } });
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-gray-800">Jurnal Mengajar Harian</h2>
        <button onClick={() => setShowForm(!showForm)} className="bg-islamic-600 text-white px-4 py-2 rounded shadow hover:bg-islamic-700">
          {showForm ? 'Batal' : '+ Tulis Jurnal'}
        </button>
      </div>

      {showForm && (
        <div className="bg-white p-6 rounded-lg shadow border-t-4 border-islamic-500">
          <h3 className="text-lg font-bold mb-4 text-center border-b pb-2">{SCHOOL_NAME} - Form Jurnal</h3>
          <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium">Tanggal</label>
              <input type="date" className="w-full border p-2 rounded" value={form.date} onChange={e => setForm({...form, date: e.target.value})} required />
            </div>
            <div>
              <label className="block text-sm font-medium">Kelas</label>
              <select className="w-full border p-2 rounded" value={form.classId} onChange={e => setForm({...form, classId: e.target.value})} required>
                <option value="">Pilih Kelas</option>
                {classes.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
              </select>
            </div>
            <div className="md:col-span-2">
              <label className="block text-sm font-medium">Materi / TP</label>
              <input type="text" className="w-full border p-2 rounded" value={form.topic} onChange={e => setForm({...form, topic: e.target.value})} required />
            </div>
            <div className="md:col-span-2">
              <label className="block text-sm font-medium">Kegiatan Pembelajaran</label>
              <textarea className="w-full border p-2 rounded h-24" value={form.activity} onChange={e => setForm({...form, activity: e.target.value})} />
            </div>

            <div className="md:col-span-2">
                <label className="block text-sm font-medium mb-1">Rekap Absensi (Jumlah Siswa)</label>
                <div className="grid grid-cols-4 gap-2">
                    <input type="number" placeholder="Hadir" className="border p-2 rounded text-center" value={form.attendanceSummary?.hadir} onChange={e => setForm({...form, attendanceSummary: {...form.attendanceSummary!, hadir: parseInt(e.target.value)}})} />
                    <input type="number" placeholder="Izin" className="border p-2 rounded text-center" value={form.attendanceSummary?.izin} onChange={e => setForm({...form, attendanceSummary: {...form.attendanceSummary!, izin: parseInt(e.target.value)}})} />
                    <input type="number" placeholder="Sakit" className="border p-2 rounded text-center" value={form.attendanceSummary?.sakit} onChange={e => setForm({...form, attendanceSummary: {...form.attendanceSummary!, sakit: parseInt(e.target.value)}})} />
                    <input type="number" placeholder="Alfa" className="border p-2 rounded text-center" value={form.attendanceSummary?.alfa} onChange={e => setForm({...form, attendanceSummary: {...form.attendanceSummary!, alfa: parseInt(e.target.value)}})} />
                </div>
            </div>

            <div className="md:col-span-2">
              <label className="block text-sm font-medium">Catatan Khusus</label>
