import React, { useState, useRef } from 'react';
import { editImageWithGemini, searchTeachingResources, SearchResult } from '../services/geminiService';

export const AITools: React.FC = () => {
    const [activeTab, setActiveTab] = useState<'image' | 'search'>('image');

    // Image Edit State
    const [selectedImage, setSelectedImage] = useState<string | null>(null);
    const [imageMime, setImageMime] = useState<string>('');
    const [prompt, setPrompt] = useState<string>('');
    const [generatedImage, setGeneratedImage] = useState<string | null>(null);
    const [loadingImage, setLoadingImage] = useState(false);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Search State
    const [searchQuery, setSearchQuery] = useState('');
    const [searchResult, setSearchResult] = useState<SearchResult | null>(null);
    const [loadingSearch, setLoadingSearch] = useState(false);

    const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onloadend = () => {
                const result = reader.result as string;
                setSelectedImage(result);
                // Extract base64 part
                setImageMime(file.type);
            };
            reader.readAsDataURL(file);
        }
    };

    const handleGenerateImage = async () => {
        if (!selectedImage || !prompt) return;
        setLoadingImage(true);
        try {
            // Remove data URL header for API
            const base64Data = selectedImage.split(',')[1];
            const result = await editImageWithGemini(base64Data, prompt, imageMime);
            setGeneratedImage(result);
        } catch (error) {
            alert("Gagal mengedit gambar. Pastikan API KEY valid.");
        } finally {
            setLoadingImage(false);
        }
    };

    const handleSearch = async () => {
        if (!searchQuery) return;
        setLoadingSearch(true);
        try {
            const result = await searchTeachingResources(searchQuery);
            setSearchResult(result);
        } catch (error) {
             alert("Gagal mencari data.");
        } finally {
            setLoadingSearch(false);
        }
    };

    return (
        <div className="space-y-6">
            <h2 className="text-2xl font-bold text-gray-800">Asisten Cerdas (AI)</h2>

            <div className="flex space-x-4 border-b">
                <button 
                    className={`py-2 px-4 ${activeTab === 'image' ? 'border-b-2 border-islamic-600 text-islamic-700 font-bold' : 'text-gray-500'}`}
                    onClick={() => setActiveTab('image')}
                >
                    🖼️ Edit Media Ajar
                </button>
                <button 
                    className={`py-2 px-4 ${activeTab === 'search' ? 'border-b-2 border-islamic-600 text-islamic-700 font-bold' : 'text-gray-500'}`}
                    onClick={() => setActiveTab('search')}
                >
                    🔍 Cari Referensi
                </button>
            </div>

            {activeTab === 'image' && (
                <div className="bg-white p-6 rounded-lg shadow space-y-4">
                    <p className="text-gray-600 mb-4">Upload materi ajar (foto/scan LKS) dan gunakan AI untuk memodifikasinya (misal: "hapus background", "ubah jadi hitam putih", "tambahkan stiker bintang").</p>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div className="space-y-4">
                            <input 
                                type="file" 
                                ref={fileInputRef}
                                onChange={handleFileChange} 
                                accept="image/*"
                                className="block w-full text-sm text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-islamic-50 file:text-islamic-700 hover:file:bg-islamic-100"
                            />
                            {selectedImage && (
                                <div className="border rounded p-2">
                                    <p className="text-xs text-gray-500 mb-1">Original:</p>
                                    <img src={selectedImage} alt="Original" className="max-h-64 object-contain" />
                                </div>
                            )}
                        </div>

                        <div className="space-y-4">
                            <textarea 
                                className="w-full border p-2 rounded" 
                                placeholder="Instruksi untuk AI: (contoh: Ubah gambar menjadi sketsa pensil)"
                                value={prompt}
                                onChange={(e) => setPrompt(e.target.value)}
                                disabled={!selectedImage}
                            />
                            <button 
                                onClick={handleGenerateImage}
                                disabled={loadingImage || !selectedImage || !prompt}
                                className="w-full bg-islamic-600 text-white py-2 rounded disabled:opacity-50"
                            >
                                {loadingImage ? 'Sedang memproses...' : '✨ Proses Gambar'}
                            </button>

                             {generatedImage && (
                                <div className="border rounded p-2 bg-islamic-50">
                                    <p className="text-xs text-gray-500 mb-1">Hasil AI:</p>
                                    <img src={generatedImage} alt="Generated" className="max-h-64 object-contain" />
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            )}

            {activeTab === 'search' && (
                <div className="bg-white p-6 rounded-lg shadow space-y-4">
                    <p className="text-gray-600">Cari referensi Kurikulum Merdeka, metode pembelajaran Bahasa Arab, atau materi terkini.</p>
                    <div className="flex gap-2">
                        <input 
                            type="text" 
                            className="flex-1 border p-2 rounded"
                            placeholder="Contoh: Metode fun learning bahasa arab untuk kelas 7"
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            onKeyDown={(e) => e.key === 'Enter' && handleSearch()}
                        />
                        <button 
                             onClick={handleSearch}
                             disabled={loadingSearch}
                             className="bg-blue-600 text-white px-6 py-2 rounded hover:bg-blue-700 disabled:opacity-50"
                        >
                            {loadingSearch ? '...' : 'Cari'}
                        </button>
                    </div>

                    {searchResult && (
                        <div className="mt-4 p-4 border rounded bg-gray-50">
                            <div className="prose max-w-none text-sm text-gray-800 whitespace-pre-line mb-4">
                                {searchResult.text}
                            </div>

                            {searchResult.links.length > 0 && (
                                <div className="border-t pt-3">
                                    <h4 className="text-xs font-bold text-gray-500 uppercase mb-2">Sumber Referensi:</h4>
                                    <ul className="space-y-1">
                                        {searchResult.links.map((link, idx) => (
                                            <li key={idx}>
                                                <a href={link.uri} target="_blank" rel="noopener noreferrer" className="text-blue-600 hover:underline text-sm flex items-center">
                                                    <span className="mr-2">🔗</span> {link.title}
                                                </a>
                                            </li>
                                        ))}
                                    </ul>
                                </div>
                            )}
                        </div>
                    )}
                </div>
            )}
        </div>
    );
};

