      </div>

      <div className="alert alert-light border mt-4">
         <strong>Informasi Kurikulum Merdeka:</strong>
         <ul className="mb-0 mt-2 text-muted small">
            <li>KKM: {KKM}</li>
            <li>Nilai Akhir = ({WEIGHTS.FORMATIF*100}% Formatif) + ({WEIGHTS.SUMATIF*100}% Sumatif Materi) + ({WEIGHTS.SAS*100}% Sumatif Akhir)</li>
         </ul>
