import React, { useState, useEffect } from 'react';
import { Classroom, Student, AttendanceData } from '../types';
import { getClasses, getStudentsByClass, getAttendanceByStudent, saveAttendance } from '../services/storageService';
import { ATTENDANCE_OPTIONS, TOTAL_MEETINGS } from '../constants';

export const AttendanceSheet: React.FC = () => {
  const [selectedClass, setSelectedClass] = useState<string>('');
  const [classes, setClasses] = useState<Classroom[]>([]);
  const [students, setStudents] = useState<Student[]>([]);
  const [attendance, setAttendance] = useState<Record<string, AttendanceData>>({});

  useEffect(() => {
    setClasses(getClasses());
  }, []);

  useEffect(() => {
    if (selectedClass) {
      const clsStudents = getStudentsByClass(selectedClass);
      setStudents(clsStudents);
      const attMap: Record<string, AttendanceData> = {};
      clsStudents.forEach(s => {
        attMap[s.id] = getAttendanceByStudent(s.id);
      });
      setAttendance(attMap);
    }
  }, [selectedClass]);

  const handleStatusChange = (studentId: string, meetingIndex: number, status: string) => {
    const current = { ...attendance[studentId] };
    const newMeetings = [...current.meetings];
    newMeetings[meetingIndex] = status;
    current.meetings = newMeetings;

    setAttendance(prev => ({ ...prev, [studentId]: current }));
    saveAttendance(current);
  };

  const countStatus = (meetings: string[], status: string) => meetings.filter(m => m === status).length;

  return (
    <div>
      <div className="d-flex justify-content-between align-items-center mb-4">
        <h2 className="text-dark">Absensi Siswa</h2>
        <div className="col-md-3">
             <select 
                className="form-select"
                value={selectedClass}
                onChange={(e) => setSelectedClass(e.target.value)}
                >
                <option value="">-- Pilih Kelas --</option>
                {classes.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
        </div>
      </div>

      {selectedClass && (
        <div className="card shadow-sm border-0">
          <div className="card-body p-0">
            <div className="table-responsive">
                <table className="table table-bordered table-sm mb-0 align-middle text-center" style={{fontSize: '0.85rem'}}>
                    <thead className="table-light">
                    <tr>
                        <th rowSpan={2} className="align-middle sticky-start bg-light" style={{left: 0, zIndex: 10, minWidth: '150px'}}>Nama Siswa</th>
                        <th colSpan={TOTAL_MEETINGS}>Pertemuan Ke-</th>
                        <th colSpan={4}>Rekap</th>
                    </tr>
                    <tr>
                        {Array.from({ length: TOTAL_MEETINGS }).map((_, i) => (
                        <th key={i} className="small text-muted">{i + 1}</th>
                        ))}
                        <th className="text-success">H</th>
                        <th className="text-primary">I</th>
                        <th className="text-warning">S</th>
                        <th className="text-danger">A</th>
                    </tr>
                    </thead>
                    <tbody>
                    {students.map(s => {
                        const att = attendance[s.id];
                        if (!att) return null;
                        return (
                        <tr key={s.id}>
                            <td className="sticky-start bg-white text-start fw-bold">{s.name}</td>
                            {Array.from({ length: TOTAL_MEETINGS }).map((_, i) => (
                            <td key={i} className="p-0" style={{minWidth: '35px'}}>
                                <select 
                                className={`form-select form-select-sm border-0 text-center p-0 shadow-none
                                    ${att.meetings[i] === 'A' ? 'text-danger fw-bold' : ''}
                                    ${att.meetings[i] === 'H' ? 'text-success fw-bold' : ''}
                                `}
                                value={att.meetings[i] || ''}
                                onChange={(e) => handleStatusChange(s.id, i, e.target.value)}
                                >
                                <option value=""></option>
                                {ATTENDANCE_OPTIONS.map(opt => <option key={opt} value={opt}>{opt}</option>)}
                                </select>
                            </td>
                            ))}
                            <td className="fw-bold bg-light">{countStatus(att.meetings, 'H')}</td>
                            <td className="bg-light">{countStatus(att.meetings, 'I')}</td>
                            <td className="bg-light">{countStatus(att.meetings, 'S')}</td>
                            <td className="text-danger fw-bold bg-light">{countStatus(att.meetings, 'A')}</td>
                        </tr>
                        );
                    })}
                    </tbody>
                </table>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { JournalEntry, Classroom } from '../types';
import { getClasses, getJournals, saveJournal } from '../services/storageService';
import { SCHOOL_NAME } from '../constants';

export const JournalManager: React.FC = () => {
  const [entries, setEntries] = useState<JournalEntry[]>([]);
  const [classes, setClasses] = useState<Classroom[]>([]);
  const [showForm, setShowForm] = useState(false);
  const [form, setForm] = useState<Partial<JournalEntry>>({
    date: new Date().toISOString().split('T')[0],
    attendanceSummary: { hadir: 0, izin: 0, sakit: 0, alfa: 0 }
  });

  useEffect(() => {
    setClasses(getClasses());
    setEntries(getJournals().sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
  }, []);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.topic || !form.classId) return;

    const entry: JournalEntry = {
      id: Date.now().toString(),
      date: form.date!,
      classId: form.classId!,
      topic: form.topic!,
      activity: form.activity || '',
      notes: form.notes || '',
      attendanceSummary: {
        hadir: Number(form.attendanceSummary?.hadir) || 0,
        izin: Number(form.attendanceSummary?.izin) || 0,
        sakit: Number(form.attendanceSummary?.sakit) || 0,
        alfa: Number(form.attendanceSummary?.alfa) || 0,
      }
    };

    saveJournal(entry);
    setEntries([entry, ...entries]);
    setShowForm(false);
    setForm({ date: new Date().toISOString().split('T')[0], attendanceSummary: { hadir: 0, izin: 0, sakit: 0, alfa: 0 } });
  };

  return (
    <div>
      <div className="d-flex justify-content-between align-items-center mb-4">
        <h2 className="text-dark">Jurnal Mengajar Harian</h2>
        <button onClick={() => setShowForm(!showForm)} className={`btn ${showForm ? 'btn-secondary' : 'btn-success'}`}>
          {showForm ? 'Batal' : '+ Tulis Jurnal'}
        </button>
      </div>

      {showForm && (
        <div className="card shadow mb-4 border-top border-success border-4">
          <div className="card-body">
            <h5 className="text-center fw-bold mb-3">{SCHOOL_NAME} - Form Jurnal</h5>
            <form onSubmit={handleSubmit}>
                <div className="row g-3">
                    <div className="col-md-6">
                        <label className="form-label">Tanggal</label>
                        <input type="date" className="form-control" value={form.date} onChange={e => setForm({...form, date: e.target.value})} required />
                    </div>
                    <div className="col-md-6">
                        <label className="form-label">Kelas</label>
                        <select className="form-select" value={form.classId} onChange={e => setForm({...form, classId: e.target.value})} required>
                            <option value="">Pilih Kelas</option>
                            {classes.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                        </select>
                    </div>
                    <div className="col-12">
                        <label className="form-label">Materi / TP</label>
                        <input type="text" className="form-control" value={form.topic} onChange={e => setForm({...form, topic: e.target.value})} required />
                    </div>
                    <div className="col-12">
                        <label className="form-label">Kegiatan Pembelajaran</label>
                        <textarea className="form-control" rows={3} value={form.activity} onChange={e => setForm({...form, activity: e.target.value})} />
                    </div>
                    <div className="col-12">
                        <label className="form-label mb-1">Rekap Absensi (Jumlah Siswa)</label>
                        <div className="row g-2">
                            <div className="col">
                                <input type="number" placeholder="Hadir" className="form-control text-center border-success" value={form.attendanceSummary?.hadir} onChange={e => setForm({...form, attendanceSummary: {...form.attendanceSummary!, hadir: parseInt(e.target.value)}})} />
                            </div>
                            <div className="col">
                                <input type="number" placeholder="Izin" className="form-control text-center border-info" value={form.attendanceSummary?.izin} onChange={e => setForm({...form, attendanceSummary: {...form.attendanceSummary!, izin: parseInt(e.target.value)}})} />
                            </div>
                            <div className="col">
                                <input type="number" placeholder="Sakit" className="form-control text-center border-warning" value={form.attendanceSummary?.sakit} onChange={e => setForm({...form, attendanceSummary: {...form.attendanceSummary!, sakit: parseInt(e.target.value)}})} />
                            </div>
                            <div className="col">
                                <input type="number" placeholder="Alfa" className="form-control text-center border-danger" value={form.attendanceSummary?.alfa} onChange={e => setForm({...form, attendanceSummary: {...form.attendanceSummary!, alfa: parseInt(e.target.value)}})} />
                            </div>
                        </div>
                    </div>
                    <div className="col-12">
                        <label className="form-label">Catatan Khusus</label>
                        <textarea className="form-control" value={form.notes} onChange={e => setForm({...form, notes: e.target.value})} />
                    </div>
                    <div className="col-12">
                        <button type="submit" className="btn btn-success w-100">Simpan Jurnal</button>
                    </div>
                </div>
            </form>
          </div>
        </div>
      )}

      <div className="row g-3">
        {entries.map(entry => (
          <div key={entry.id} className="col-12">
            <div className="card shadow-sm h-100 hover-shadow">
                <div className="card-body">
                    <div className="d-flex justify-content-between align-items-start border-bottom pb-2 mb-2">
                        <div>
                            <h5 className="fw-bold text-success mb-1">{entry.topic}</h5>
                            <small className="text-muted">
                                {new Date(entry.date).toLocaleDateString('id-ID', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })} • 
                                Kelas: {classes.find(c => c.id === entry.classId)?.name || '?'}
                            </small>
                        </div>
                    </div>
                    <p className="card-text text-dark mb-3" style={{whiteSpace: 'pre-line'}}>
                        <strong>Kegiatan:</strong> {entry.activity}
                    </p>
                    <div className="bg-light p-2 rounded d-flex gap-3 small mb-2">
                        <span>✅ H: {entry.attendanceSummary.hadir}</span>
                        <span>ℹ️ I: {entry.attendanceSummary.izin}</span>
                        <span>🏥 S: {entry.attendanceSummary.sakit}</span>
                        <span>❌ A: {entry.attendanceSummary.alfa}</span>
                    </div>
                    {entry.notes && (
                        <div className="alert alert-warning py-1 px-2 small mb-0 fst-italic">
                            Note: {entry.notes}
                        </div>
                    )}
                </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

