const { DataTypes } = require('sequelize');

module.exports = (sequelize) => {
  const Nilai = sequelize.define('Nilai', {
    formatif: { type: DataTypes.JSON }, // Store array [80, 90, ...]
    sumatif: { type: DataTypes.JSON },
    sas_non_tes: { type: DataTypes.FLOAT },
    sas_tes: { type: DataTypes.FLOAT },
    nilai_rapor: { type: DataTypes.FLOAT },
    status: { type: DataTypes.ENUM('Tuntas', 'Belum Tuntas') }
  }, {
    hooks: {
      beforeSave: (nilai) => {
        // Calculate Logic
        const avg = (arr) => arr.reduce((a,b)=>a+b,0) / arr.length || 0;
        const f = avg(nilai.formatif);
        const s = avg(nilai.sumatif);
        const sas = (nilai.sas_non_tes + nilai.sas_tes) / 2;

        nilai.nilai_rapor = (f * 0.4) + (s * 0.3) + (sas * 0.3);
        nilai.status = nilai.nilai_rapor >= 72 ? 'Tuntas' : 'Belum Tuntas';
      }
    }
  });
  return Nilai;
};
```

