exports.importClass71 = async (req, res) => {
  const t = await sequelize.transaction(); // Mulai transaksi database

  try {
    // 1. Cek atau Buat Kelas 7.1
    // findOrCreate mengembalikan array [instance, created]
    const [kelas, created] = await Kelas.findOrCreate({
      where: { 
        nama_kelas: '7.1', 
        semester: 'Ganjil', 
        tahun_ajaran: '2025/2026' 
      },
      defaults: {
        nama_kelas: '7.1',
        semester: 'Ganjil',
        tahun_ajaran: '2025/2026'
      },
      transaction: t
    });

    console.log(created ? 'Kelas 7.1 dibuat.' : 'Kelas 7.1 sudah ada.');

    let successCount = 0;
    let skipCount = 0;

    // 2. Loop insert siswa
    for (const nama of studentList) {
      // Cek duplikasi berdasarkan nama & kelas_id
      const existingStudent = await Siswa.findOne({
        where: {
          nama: nama,
          kelas_id: kelas.id
        },
        transaction: t
      });

      if (!existingStudent) {
        await Siswa.create({
          nama: nama,
          kelas_id: kelas.id,
          jenis_kelamin: guessGender(nama),
          nisn: null // Biarkan null dulu sesuai request
        }, { transaction: t });
        successCount++;
      } else {
        skipCount++;
      }
    }

    // 3. Commit transaksi jika semua lancar
    await t.commit();

    res.json({
      message: 'Import Data Kelas 7.1 Selesai',
      class_id: kelas.id,
      imported: successCount,
      skipped: skipCount,
      total_students: studentList.length
    });

  } catch (error) {
    // 4. Rollback jika ada error
    await t.rollback();
    console.error(error);
    res.status(500).json({ 
      message: 'Gagal melakukan import', 
      error: error.message 
    });
  }
};
