import React, { useState, useEffect } from 'react';
import { Classroom, Student, AttendanceData } from '../types';
import { getClasses, getStudentsByClass, getAttendanceByStudent, saveAttendance } from '../services/storageService';
import { ATTENDANCE_OPTIONS, TOTAL_MEETINGS } from '../constants';

export const AttendanceSheet: React.FC = () => {
  const [selectedClass, setSelectedClass] = useState<string>('');
  const [classes, setClasses] = useState<Classroom[]>([]);
  const [students, setStudents] = useState<Student[]>([]);
  const [attendance, setAttendance] = useState<Record<string, AttendanceData>>({});

  useEffect(() => {
    setClasses(getClasses());
  }, []);

  useEffect(() => {
    if (selectedClass) {
      // Data students sudah otomatis terurut A-Z dari storageService
      const clsStudents = getStudentsByClass(selectedClass);
      setStudents(clsStudents);
      const attMap: Record<string, AttendanceData> = {};
      clsStudents.forEach(s => {
        attMap[s.id] = getAttendanceByStudent(s.id);
      });
      setAttendance(attMap);
    }
  }, [selectedClass]);

  const handleStatusChange = (studentId: string, meetingIndex: number, status: string) => {
    const current = { ...attendance[studentId] };
    const newMeetings = [...current.meetings];
    newMeetings[meetingIndex] = status;
    current.meetings = newMeetings;

    setAttendance(prev => ({ ...prev, [studentId]: current }));
    saveAttendance(current);
  };

  const countStatus = (meetings: string[], status: string) => meetings.filter(m => m === status).length;

  const getStatusClass = (status: string) => {
    switch (status) {
      case 'H': return 'bg-att-H';
      case 'I': return 'bg-att-I';
      case 'S': return 'bg-att-S';
      case 'A': return 'bg-att-A';
      default: return 'bg-white';
    }
  };

  // --- Export Functions ---
  const handleExport = (type: 'excel' | 'word' | 'print') => {
    if (!selectedClass) return;
    const className = classes.find(c => c.id === selectedClass)?.name || 'Kelas';

    if (type === 'print') {
        window.print();
        return;
    }

    let content = '';
    const tableHTML = document.getElementById('attendance-table')?.outerHTML;

    if (!tableHTML) return;

    if (type === 'excel') {
        content = `
            <html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:x="urn:schemas-microsoft-com:office:excel" xmlns="http://www.w3.org/TR/REC-html40">
            <head><!--[if gte mso 9]><xml><x:ExcelWorkbook><x:ExcelWorksheets><x:ExcelWorksheet><x:Name>Absensi ${className}</x:Name><x:WorksheetOptions><x:DisplayGridlines/></x:WorksheetOptions></x:ExcelWorksheet></x:ExcelWorksheets></x:ExcelWorkbook></xml><![endif]--></head>
            <body>${tableHTML}</body></html>`;
        const blob = new Blob([content], { type: 'application/vnd.ms-excel' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `Absensi_${className}.xls`;
        a.click();
    } else if (type === 'word') {
        content = `
            <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
            <head><meta charset='utf-8'><title>Absensi ${className}</title></head>
            <body>
            <h2>Laporan Absensi Kelas ${className}</h2>
            ${tableHTML}
            </body></html>`;
        const blob = new Blob([content], { type: 'application/msword' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `Absensi_${className}.doc`;
        a.click();
    }
  };

  return (
    <div>
      <div className="d-flex justify-content-between align-items-center mb-4 no-print">
        <h2 className="text-dark">Absensi Siswa</h2>
        <div className="d-flex gap-2">
            <select 
                className="form-select"
                value={selectedClass}
                onChange={(e) => setSelectedClass(e.target.value)}
            >
                <option value="">-- Pilih Kelas --</option>
                {classes.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>

            {selectedClass && (
                <div className="dropdown">
                    <button className="btn btn-primary dropdown-toggle" type="button" data-bs-toggle="dropdown">
                        📥 Backup Data
                    </button>
                    <ul className="dropdown-menu">
                        <li><button className="dropdown-item" onClick={() => handleExport('excel')}>📊 Export Excel</button></li>
                        <li><button className="dropdown-item" onClick={() => handleExport('word')}>📄 Export Word</button></li>
                        <li><button className="dropdown-item" onClick={() => handleExport('print')}>🖨️ Print / PDF</button></li>
                    </ul>
                </div>
            )}
        </div>
      </div>

      {selectedClass && (
        <div className="card shadow-sm border-0">
          <div className="card-body p-0">
             {/* Legend */}
             <div className="p-3 border-bottom bg-light d-flex gap-3 flex-wrap">
                <span className="fw-bold">Keterangan:</span>
                <span className="badge bg-att-H text-dark border">H = Hadir</span>
                <span className="badge bg-att-I text-dark border">I = Izin</span>
                <span className="badge bg-att-S text-dark border">S = Sakit</span>
                <span className="badge bg-att-A text-dark border">A = Alfa</span>
             </div>

            <div className="table-responsive" style={{maxHeight: '75vh'}}>
                <table id="attendance-table" className="table table-bordered mb-0 align-middle text-center" style={{fontSize: '0.9rem'}}>
                    <thead className="table-light sticky-header">
                    <tr>
                        <th rowSpan={2} className="align-middle sticky-col sticky-header-col p-3" style={{minWidth: '250px', left: 0}}>
                            NAMA SISWA (A-Z)
                        </th>
                        <th colSpan={TOTAL_MEETINGS} className="text-center py-2 bg-light sticky-header">Pertemuan Ke-</th>
                        <th colSpan={4} className="text-center bg-light sticky-header">Total</th>
                    </tr>
                    <tr>
                        {Array.from({ length: TOTAL_MEETINGS }).map((_, i) => (
                        <th key={i} className="small text-muted sticky-header bg-white" style={{minWidth: '60px'}}>{i + 1}</th>
                        ))}
                        <th className="bg-success text-white sticky-header">H</th>
                        <th className="bg-warning text-dark sticky-header">I</th>
                        <th className="bg-info text-white sticky-header">S</th>
                        <th className="bg-danger text-white sticky-header">A</th>
                    </tr>
                    </thead>
                    <tbody>
                    {students.map(s => {
                        const att = attendance[s.id];
                        if (!att) return null;
                        return (
                        <tr key={s.id}>
                            <td className="sticky-col text-start fw-bold px-3 py-2 bg-white">{s.name}</td>
                            {Array.from({ length: TOTAL_MEETINGS }).map((_, i) => (
                            <td key={i} className="p-0">
                                <select 
                                    className={`form-select border-0 shadow-none att-select ${getStatusClass(att.meetings[i])}`}
                                    value={att.meetings[i] || ''}
                                    onChange={(e) => handleStatusChange(s.id, i, e.target.value)}
                                >
                                    <option value="">-</option>
                                    {ATTENDANCE_OPTIONS.map(opt => <option key={opt} value={opt}>{opt}</option>)}
                                </select>
                            </td>
                            ))}
                            <td className="fw-bold">{countStatus(att.meetings, 'H')}</td>
                            <td>{countStatus(att.meetings, 'I')}</td>
                            <td>{countStatus(att.meetings, 'S')}</td>
                            <td className="fw-bold text-danger">{countStatus(att.meetings, 'A')}</td>
                        </tr>
                        );
                    })}
                    </tbody>
                </table>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Student, GradeData, Classroom } from '../types';
import { getClasses, getStudentsByClass, getGradeByStudent, saveGrade } from '../services/storageService';
import { KKM, WEIGHTS } from '../constants';

export const GradingSheet: React.FC = () => {
  const [selectedClass, setSelectedClass] = useState<string>('');
  const [classes, setClasses] = useState<Classroom[]>([]);
  const [students, setStudents] = useState<Student[]>([]);
  const [grades, setGrades] = useState<Record<string, GradeData>>({});

  useEffect(() => {
    setClasses(getClasses());
  }, []);

  useEffect(() => {
    if (selectedClass) {
      // Data students already sorted A-Z from service
      const clsStudents = getStudentsByClass(selectedClass);
      setStudents(clsStudents);
      const gradeMap: Record<string, GradeData> = {};
      clsStudents.forEach(s => {
        gradeMap[s.id] = getGradeByStudent(s.id);
      });
      setGrades(gradeMap);
    }
  }, [selectedClass]);

  const handleGradeChange = (studentId: string, field: 'formatif' | 'sumatif', index: number, value: string) => {
    const numVal = parseFloat(value) || 0;
    const currentGrade = { ...grades[studentId] };
    if (field === 'formatif') {
      const newF = [...currentGrade.formatif];
      newF[index] = numVal;
      currentGrade.formatif = newF;
    } else {
      const newS = [...currentGrade.sumatif];
      newS[index] = numVal;
      currentGrade.sumatif = newS;
    }
    setGrades(prev => ({ ...prev, [studentId]: currentGrade }));
    saveGrade(currentGrade);
  };

  const handleSasChange = (studentId: string, field: 'sasNonTes' | 'sasTes', value: string) => {
    const numVal = parseFloat(value) || 0;
    const currentGrade = { ...grades[studentId], [field]: numVal };
    setGrades(prev => ({ ...prev, [studentId]: currentGrade }));
    saveGrade(currentGrade);
  };

  const getLetterGrade = (score: number) => {
      if (score >= 90) return { letter: 'A', color: 'bg-success' };
      if (score >= 80) return { letter: 'B', color: 'bg-primary' };
      if (score >= 70) return { letter: 'C', color: 'bg-info text-dark' };
      if (score >= 60) return { letter: 'D', color: 'bg-warning text-dark' };
      return { letter: 'E', color: 'bg-danger' };
  };

  // Automated Calculations & Ranking
  const calculatedData = useMemo(() => {
    // 1. Calculate scores for everyone
    const processed = students.map(s => {
      const g = grades[s.id];
      if (!g) return null;

      const validF = g.formatif.filter(n => n > 0);
      const avgF = validF.length > 0 ? validF.reduce((a, b) => a + b, 0) / validF.length : 0;

      const validS = g.sumatif.filter(n => n > 0);
      const avgS = validS.length > 0 ? validS.reduce((a, b) => a + b, 0) / validS.length : 0;

      const sas = (g.sasNonTes + g.sasTes) / 2;

      const final = (avgF * WEIGHTS.FORMATIF) + (avgS * WEIGHTS.SUMATIF) + (sas * WEIGHTS.SAS);
      const isPassing = final >= KKM;
      const letter = getLetterGrade(final);

      return {
        ...s,
        avgF,
        avgS,
        sas,
        final,
        isPassing,
        letter
      };
    });

    // 2. Determine Ranks based on Score DESC
    // Filter out nulls first
    const validProcessed = processed.filter(p => p !== null) as NonNullable<typeof processed[0]>[];

    // Sort copy by final score DESC to determine rank
    const sortedByScore = [...validProcessed].sort((a, b) => b.final - a.final);

    // Create Map for Rank
    const rankMap: Record<string, number> = {};
    sortedByScore.forEach((item, index) => {
        rankMap[item.id] = index + 1;
    });

    // 3. Return original A-Z list with Rank attached
    return validProcessed.map(item => ({
        ...item,
        rank: rankMap[item.id]
    }));

  }, [students, grades]);

  // Stats
  const stats = useMemo(() => {
    if (!calculatedData.length) return null;
    const scores = calculatedData.map(d => d.final).filter(s => s > 0);
    if (!scores.length) return null;
    return {
      max: Math.max(...scores),
      min: Math.min(...scores),
      avg: scores.reduce((a,b) => a+b,0) / scores.length,
      tuntas: calculatedData.filter(d => d.isPassing).length,
      belum: calculatedData.filter(d => !d.isPassing).length,
    };
  }, [calculatedData]);

  // --- Export Functions ---
  const handleExport = (type: 'excel' | 'word' | 'print') => {
    if (!selectedClass) return;
    const className = classes.find(c => c.id === selectedClass)?.name || 'Kelas';

    if (type === 'print') {
        window.print();
        return;
    }

    let content = '';
    const tableHTML = document.getElementById('grading-table')?.outerHTML;

    if (!tableHTML) return;

    if (type === 'excel') {
        content = `
            <html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:x="urn:schemas-microsoft-com:office:excel" xmlns="http://www.w3.org/TR/REC-html40">
            <head><!--[if gte mso 9]><xml><x:ExcelWorkbook><x:ExcelWorksheets><x:ExcelWorksheet><x:Name>Nilai ${className}</x:Name><x:WorksheetOptions><x:DisplayGridlines/></x:WorksheetOptions></x:ExcelWorksheet></x:ExcelWorksheets></x:ExcelWorkbook></xml><![endif]--></head>
            <body>${tableHTML}</body></html>`;
        const blob = new Blob([content], { type: 'application/vnd.ms-excel' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `Nilai_${className}.xls`;
        a.click();
    } else if (type === 'word') {
        content = `
            <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
            <head><meta charset='utf-8'><title>Nilai ${className}</title></head>
            <body>
            <h2>Laporan Nilai Kelas ${className}</h2>
            ${tableHTML}
            </body></html>`;
        const blob = new Blob([content], { type: 'application/msword' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `Nilai_${className}.doc`;
        a.click();
    }
  };

  if (!classes.length) return <div className="alert alert-warning">Belum ada kelas. Silakan tambah kelas dulu.</div>;

  return (
    <div>
      <div className="d-flex justify-content-between align-items-center mb-4 no-print">
        <h2 className="text-dark">Rekap Nilai Kurikulum Merdeka</h2>
        <div className="d-flex gap-2">
            <select 
                className="form-select"
                value={selectedClass}
                onChange={(e) => setSelectedClass(e.target.value)}
            >
            <option value="">-- Pilih Kelas --</option>
            {classes.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>

            {selectedClass && (
                <div className="dropdown">
                    <button className="btn btn-primary dropdown-toggle" type="button" data-bs-toggle="dropdown">
                        📥 Backup Data
                    </button>
                    <ul className="dropdown-menu">
                        <li><button className="dropdown-item" onClick={() => handleExport('excel')}>📊 Export Excel</button></li>
                        <li><button className="dropdown-item" onClick={() => handleExport('word')}>📄 Export Word</button></li>
                        <li><button className="dropdown-item" onClick={() => handleExport('print')}>🖨️ Print / PDF</button></li>
                    </ul>
                </div>
            )}
        </div>
      </div>

      {selectedClass && stats && (
        <div className="card mb-4 border-0 shadow-sm">
            <div className="card-body">
                <div className="row text-center">
                    <div className="col border-end">
                        <small className="text-muted d-block">Tertinggi</small>
                        <span className="fw-bold text-success">{stats.max.toFixed(1)}</span>
                    </div>
                    <div className="col border-end">
                        <small className="text-muted d-block">Terendah</small>
                        <span className="fw-bold text-danger">{stats.min.toFixed(1)}</span>
                    </div>
                    <div className="col border-end">
                        <small className="text-muted d-block">Rata-rata</small>
                        <span className="fw-bold text-primary">{stats.avg.toFixed(1)}</span>
                    </div>
                    <div className="col border-end">
                        <small className="text-muted d-block">Tuntas</small>
                        <span className="fw-bold text-success">{stats.tuntas}</span>
                    </div>
                    <div className="col">
                        <small className="text-muted d-block">Belum</small>
                        <span className="fw-bold text-danger">{stats.belum}</span>
                    </div>
                </div>
            </div>
        </div>
      )}

      {selectedClass && (
        <div className="card shadow-sm border-0">
          <div className="card-body p-0">
            <div className="table-responsive">
                <table id="grading-table" className="table table-bordered table-sm mb-0 align-middle text-center" style={{fontSize: '0.85rem'}}>
                <thead className="bg-success text-white sticky-header">
                    <tr>
                    <th rowSpan={2} className="align-middle sticky-col sticky-header-col p-2" style={{left: 0, minWidth: '40px'}}>No</th>
                    <th rowSpan={2} className="align-middle sticky-col sticky-header-col p-2" style={{left: '40px', minWidth: '200px'}}>Nama Siswa (A-Z)</th>
                    <th colSpan={9} className="py-1 bg-light">Formatif (40%)</th>
                    <th colSpan={6} className="py-1 bg-light">Sumatif Materi (30%)</th>
                    <th colSpan={3} className="py-1 bg-light">SAS (30%)</th>
                    <th colSpan={3} className="align-middle bg-success text-white">Hasil Akhir</th>
                    </tr>
                    <tr>
                    {/* F1-F8 + Avg */}
                    {[1,2,3,4,5,6,7,8].map(i => <th key={`fh-${i}`} className="bg-white" style={{minWidth: '35px'}}>F{i}</th>)}
                    <th className="bg-dark text-white">Rata</th>

                    {/* S1-S5 + Avg */}
                    {[1,2,3,4,5].map(i => <th key={`sh-${i}`} className="bg-white" style={{minWidth: '35px'}}>S{i}</th>)}
                    <th className="bg-dark text-white">Rata</th>

                    {/* SAS */}
                    <th className="bg-white" style={{minWidth: '40px'}}>Non</th>
                    <th className="bg-white" style={{minWidth: '40px'}}>Tes</th>
                    <th className="bg-dark text-white">NA</th>

                    {/* Final */}
                    <th className="bg-success text-white">Angka</th>
                    <th className="bg-success text-white">Huruf</th>
                    <th className="bg-success text-white">Rank</th>
                    </tr>
                </thead>
                <tbody>
                    {calculatedData.map((s, idx) => {
                    const g = grades[s.id];
                    return (
                        <tr key={s.id}>
                        <td className="sticky-col bg-white">{idx + 1}</td>
                        <td className="sticky-col bg-white text-start fw-bold px-2">{s.name}</td>

                        {/* Formatif Inputs */}
                        {g.formatif.map((val, i) => (
                            <td key={`f-${i}`} className="p-0">
                            <input type="text" className="form-control form-control-sm border-0 text-center p-0" 
                                value={val || ''} 
                                onChange={(e) => handleGradeChange(s.id, 'formatif', i, e.target.value)} 
                            />
                            </td>
                        ))}
                        <td className="fw-bold bg-light">{s.avgF.toFixed(0)}</td>

                        {/* Sumatif Inputs */}
                        {g.sumatif.map((val, i) => (
                            <td key={`s-${i}`} className="p-0">
                            <input type="text" className="form-control form-control-sm border-0 text-center p-0" 
                                value={val || ''} 
                                onChange={(e) => handleGradeChange(s.id, 'sumatif', i, e.target.value)} 
                            />
                            </td>
                        ))}
                        <td className="fw-bold bg-light">{s.avgS.toFixed(0)}</td>

                        {/* SAS Inputs */}
                        <td className="p-0">
                            <input type="text" className="form-control form-control-sm border-0 text-center p-0" 
                                value={g.sasNonTes || ''} 
                                onChange={(e) => handleSasChange(s.id, 'sasNonTes', e.target.value)} 
                            />
                        </td>
                        <td className="p-0">
                            <input type="text" className="form-control form-control-sm border-0 text-center p-0" 
                                value={g.sasTes || ''} 
                                onChange={(e) => handleSasChange(s.id, 'sasTes', e.target.value)} 
                            />
                        </td>
                        <td className="fw-bold bg-light">{s.sas.toFixed(0)}</td>

                        {/* Final */}
                        <td className="fw-bold table-active" style={{fontSize: '1.1em'}}>{s.final.toFixed(0)}</td>
                        <td>
                            <span className={`badge ${s.letter.color} d-block w-100 py-2`}>
                                {s.letter.letter}
                            </span>
                        </td>
                        <td className="fw-bold text-primary">#{s.rank}</td>
                        </tr>
                    );
                    })}
                </tbody>
                </table>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

# Backend Setup Guide (Node.js/Laravel + MySQL)

## 1. Database Schema & Relasi (Migration)

Pastikan tabel memiliki `ON DELETE CASCADE`.

**Laravel Migration: Siswa**
```php
Schema::create('siswas', function (Blueprint $table) {
    $table->id();
    $table->foreignId('kelas_id')->constrained('kelas')->onDelete('cascade');
    $table->string('nama');
    $table->enum('jenis_kelamin', ['L', 'P']);
    $table->timestamps();
});
```

**Laravel Migration: Nilai**
```php
Schema::create('nilais', function (Blueprint $table) {
    $table->id();
    $table->foreignId('siswa_id')->constrained('siswas')->onDelete('cascade');
    // ... field nilai lainnya
});
```

## 2. Controller Logic (Sorting & Analysis)

**SiswaController.php**
Pastikan selalu menggunakan `orderBy('nama', 'asc')`.

```php
public function index(Request $request) {
    $kelasId = $request->query('kelas_id');
    $siswas = Siswa::where('kelas_id', $kelasId)
                   ->orderBy('nama', 'asc') // WAJIB A-Z
                   ->get();
    return response()->json($siswas);
}
```

**NilaiController.php (Analisis & Ranking)**

```php
public function getRekap($kelasId) {
    // Ambil siswa urut abjad
    $siswas = Siswa::where('kelas_id', $kelasId)->orderBy('nama', 'asc')->with('nilai')->get();

    $data = $siswas->map(function($siswa) {
        // Hitung Nilai Akhir di Backend
        $nilai = $siswa->nilai; 
        $avgF = ...; // Hitung rata2 formatif
        $avgS = ...; // Hitung rata2 sumatif
        $sas = ($nilai->sas_non_tes + $nilai->sas_tes) / 2;
        $akhir = ($avgF * 0.4) + ($avgS * 0.3) + ($sas * 0.3);

        // Huruf
        if ($akhir >= 90) $huruf = 'A';
        else if ($akhir >= 80) $huruf = 'B';
        else if ($akhir >= 70) $huruf = 'C';
        else if ($akhir >= 60) $huruf = 'D';
        else $huruf = 'E';

        return [
            'id' => $siswa->id,
            'nama' => $siswa->nama,
            'nilai_akhir' => $akhir,
            'huruf' => $huruf
        ];
    });

    // Hitung Ranking (tanpa mengubah urutan $data utama)
    $scores = $data->pluck('nilai_akhir')->sortDesc()->values();

    $finalData = $data->map(function($item) use ($scores) {
        // Cari index + 1 untuk ranking
        $rank = $scores->search($item['nilai_akhir']) + 1;
        $item['rank'] = $rank;
        return $item;
    });

    return response()->json($finalData);
}
```

## 3. Export Data (Laravel Excel)

Untuk fitur backup/export di Backend sesungguhnya, disarankan menggunakan package `maatwebsite/excel`.

**Install:**
`composer require maatwebsite/excel`

**Export Class:**
```php
class NilaiExport implements FromCollection, WithHeadings {
