import { Student, Classroom, GradeData, AttendanceData, JournalEntry, Gender } from '../types';
import { MOCK_CLASSES } from '../constants';

// Keys
const KEYS = {
  CLASSES: 'ar_classes',
  STUDENTS: 'ar_students',
  GRADES: 'ar_grades',
  ATTENDANCE: 'ar_attendance',
  JOURNAL: 'ar_journal',
  SEEDED: 'ar_seeded_v1' // Flag untuk menandai data awal sudah masuk
};

// Helpers
const get = <T,>(key: string, defaultVal: T): T => {
  const data = localStorage.getItem(key);
  return data ? JSON.parse(data) : defaultVal;
};

const set = <T,>(key: string, data: T) => {
  localStorage.setItem(key, JSON.stringify(data));
};

// Helper: Simple Gender Guesser based on Name
const guessGender = (name: string): Gender => {
  const lower = name.toLowerCase();
  if (lower.includes('putri') || lower.includes('nur') || lower.includes('siti') || lower.includes('zahra') || lower.includes('aira') || lower.includes('syifa') || lower.includes('ina')) {
    return Gender.P;
  }
  return Gender.L; // Default to L if unsure/male
};

