import React, { useState, useEffect } from 'react';
import { Student, Classroom, Gender } from '../types';
import { getStudents, saveStudent, deleteStudent, getClasses } from '../services/storageService';

export const StudentManager: React.FC = () => {
  const [students, setStudents] = useState<Student[]>([]);
  const [classes, setClasses] = useState<Classroom[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterClass, setFilterClass] = useState('');

  // Pagination state
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 10;

  const [form, setForm] = useState<Partial<Student>>({
    nisn: '', name: '', gender: Gender.L, classId: ''
  });
  const [editingId, setEditingId] = useState<string | null>(null);

  useEffect(() => {
    refresh();
    setClasses(getClasses());
  }, []);

  const refresh = () => setStudents(getStudents());

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.name || !form.classId) return;

    const student: Student = {
      id: editingId || Date.now().toString(),
      nisn: form.nisn || '',
      name: form.name,
      gender: form.gender || Gender.L,
      classId: form.classId
    };

    saveStudent(student);
    setForm({ nisn: '', name: '', gender: Gender.L, classId: form.classId }); // Keep class selected
    setEditingId(null);
    refresh();
  };

  const handleEdit = (s: Student) => {
    setForm(s);
    setEditingId(s.id);
  };

  const handleDelete = (id: string, name: string) => {
    if (confirm(`Yakin ingin menghapus data siswa: ${name}?\n\nPERINGATAN: Data nilai dan absensi siswa ini juga akan terhapus permanen.`)) {
      deleteStudent(id);
      refresh();
    }
  };

  // Filter Logic
  const filteredStudents = students.filter(s => {
    const matchName = s.name.toLowerCase().includes(searchTerm.toLowerCase());
    const matchClass = filterClass ? s.classId === filterClass : true;
    return matchName && matchClass;
  });

  // Pagination Logic
  const totalPages = Math.ceil(filteredStudents.length / itemsPerPage);
  const currentData = filteredStudents.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);

  // --- Export Functions ---
  const handleExport = (type: 'excel' | 'word' | 'print') => {
    const className = filterClass ? classes.find(c => c.id === filterClass)?.name : 'Semua_Kelas';
    const fileName = `Data_Siswa_${className}`;

    if (type === 'print') {
        window.print();
        return;
    }

    let content = '';
    // We export the full filtered list, not just current page
    let tableRows = '';
    filteredStudents.forEach((s, idx) => {
        tableRows += `
            <tr>
                <td>${idx + 1}</td>
                <td>${s.nisn}</td>
                <td>${s.name}</td>
                <td>${s.gender}</td>
                <td>${classes.find(c => c.id === s.classId)?.name || '-'}</td>
            </tr>
        `;
    });

    const tableHTML = `
        <table border="1" style="width:100%; border-collapse:collapse;">
            <thead>
                <tr style="background-color:#eee;">
                    <th>No</th><th>NISN</th><th>Nama Lengkap</th><th>L/P</th><th>Kelas</th>
                </tr>
            </thead>
            <tbody>${tableRows}</tbody>
        </table>
    `;

    if (type === 'excel') {
        content = `
            <html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:x="urn:schemas-microsoft-com:office:excel" xmlns="http://www.w3.org/TR/REC-html40">
            <head><!--[if gte mso 9]><xml><x:ExcelWorkbook><x:ExcelWorksheets><x:ExcelWorksheet><x:Name>Data Siswa</x:Name><x:WorksheetOptions><x:DisplayGridlines/></x:WorksheetOptions></x:ExcelWorksheet></x:ExcelWorksheets></x:ExcelWorkbook></xml><![endif]--></head>
            <body>
            <h3>Data Siswa - ${className}</h3>
            ${tableHTML}
            </body></html>`;
        const blob = new Blob([content], { type: 'application/vnd.ms-excel' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `${fileName}.xls`;
        a.click();
    } else if (type === 'word') {
        content = `
            <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
            <head><meta charset='utf-8'><title>Data Siswa</title></head>
            <body>
            <h2>Data Siswa - ${className}</h2>
            ${tableHTML}
            </body></html>`;
        const blob = new Blob([content], { type: 'application/msword' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `${fileName}.doc`;
        a.click();
    }
