            </div>
            ))
        )}
      </div>
    </div>
  );
};

# Backend Setup Guide (Node.js/Laravel + MySQL)

## 1. Database Schema & Relasi (Migration)

Pastikan tabel memiliki `ON DELETE CASCADE`.

**Laravel Migration: Siswa**
```php
Schema::create('siswas', function (Blueprint $table) {
    $table->id();
    $table->foreignId('kelas_id')->constrained('kelas')->onDelete('cascade');
    $table->string('nama');
    $table->enum('jenis_kelamin', ['L', 'P']);
    $table->timestamps();
});
```

**Laravel Migration: Nilai**
```php
Schema::create('nilais', function (Blueprint $table) {
    $table->id();
    $table->foreignId('siswa_id')->constrained('siswas')->onDelete('cascade');
    // ... field nilai lainnya
});
```

## 2. Controller Logic (Sorting & Analysis)

**SiswaController.php**
Pastikan selalu menggunakan `orderBy('nama', 'asc')`.

```php
public function index(Request $request) {
    $kelasId = $request->query('kelas_id');
    $siswas = Siswa::where('kelas_id', $kelasId)
                   ->orderBy('nama', 'asc') // WAJIB A-Z
                   ->get();
    return response()->json($siswas);
}
```

**NilaiController.php (Analisis & Ranking)**

```php
public function getRekap($kelasId) {
    // Ambil siswa urut abjad
    $siswas = Siswa::where('kelas_id', $kelasId)->orderBy('nama', 'asc')->with('nilai')->get();

    $data = $siswas->map(function($siswa) {
        // Hitung Nilai Akhir di Backend
        $nilai = $siswa->nilai; 
        $avgF = ...; // Hitung rata2 formatif
        $avgS = ...; // Hitung rata2 sumatif
        $sas = ($nilai->sas_non_tes + $nilai->sas_tes) / 2;
        $akhir = ($avgF * 0.4) + ($avgS * 0.3) + ($sas * 0.3);

        // Huruf
        if ($akhir >= 90) $huruf = 'A';
        else if ($akhir >= 80) $huruf = 'B';
        else if ($akhir >= 70) $huruf = 'C';
        else if ($akhir >= 60) $huruf = 'D';
        else $huruf = 'E';

        return [
            'id' => $siswa->id,
            'nama' => $siswa->nama,
            'nilai_akhir' => $akhir,
            'huruf' => $huruf
        ];
    });

    // Hitung Ranking (tanpa mengubah urutan $data utama)
    $scores = $data->pluck('nilai_akhir')->sortDesc()->values();

    $finalData = $data->map(function($item) use ($scores) {
        // Cari index + 1 untuk ranking
        $rank = $scores->search($item['nilai_akhir']) + 1;
        $item['rank'] = $rank;
        return $item;
    });

    return response()->json($finalData);
}
```

## 3. Export Data (Laravel Excel)

Untuk fitur backup/export di Backend sesungguhnya, disarankan menggunakan package `maatwebsite/excel`.

**Install:**
`composer require maatwebsite/excel`

**Export Class (Nilai):**
```php
class NilaiExport implements FromCollection, WithHeadings {
    public function collection() {
        return Siswa::where('kelas_id', $this->kelasId)
            ->orderBy('nama', 'asc')
            ->get()
            ->map(function($s) {
                return [
                    'Nama' => $s->nama,
                    'Nilai Akhir' => $s->nilai_akhir,
                    'Huruf' => $s->huruf
                ];
            });
    }
}
```

**Export Class (Jurnal Mengajar):**
```php
class JurnalExport implements FromCollection, WithHeadings {
    public function collection() {
        return Jurnal::orderBy('tanggal', 'desc')->get()->map(function($j) {
            return [
                'Tanggal' => $j->tanggal,
                'Kelas' => $j->kelas->nama_kelas,
                'Materi' => $j->materi,
                'Kegiatan' => $j->kegiatan,
                'Hadir' => $j->hadir,
                'Sakit' => $j->sakit,
                'Izin' => $j->izin,
                'Alfa' => $j->alfa,
                'Catatan' => $j->catatan
            ];
        });
    }
}
```

**Controller Download:**
```php
public function exportExcel($kelasId) {
    return Excel::download(new NilaiExport($kelasId), 'rekap_nilai.xlsx');
}

public function exportJurnal() {
    return Excel::download(new JurnalExport(), 'jurnal_guru.xlsx');
}
```

import React, { useState, useEffect } from 'react';
import { Student, Classroom, Gender } from '../types';
import { getStudents, saveStudent, deleteStudent, getClasses } from '../services/storageService';
import { SCHOOL_NAME } from '../constants';

export const StudentManager: React.FC = () => {
  const [students, setStudents] = useState<Student[]>([]);
  const [classes, setClasses] = useState<Classroom[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterClass, setFilterClass] = useState('');

  // Pagination state
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 10;

  const [form, setForm] = useState<Partial<Student>>({
    nisn: '', name: '', gender: Gender.L, classId: ''
  });
  const [editingId, setEditingId] = useState<string | null>(null);

  useEffect(() => {
    refresh();
    setClasses(getClasses());
  }, []);

  const refresh = () => setStudents(getStudents());

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.name || !form.classId) return;

    const student: Student = {
      id: editingId || Date.now().toString(),
      nisn: form.nisn || '',
      name: form.name,
      gender: form.gender || Gender.L,
      classId: form.classId
    };

    saveStudent(student);
    setForm({ nisn: '', name: '', gender: Gender.L, classId: form.classId }); // Keep class selected
    setEditingId(null);
    refresh();
  };

  const handleEdit = (s: Student) => {
    setForm(s);
    setEditingId(s.id);
  };

  const handleDelete = (id: string, name: string) => {
    if (confirm(`Yakin ingin menghapus data siswa: ${name}?\n\nPERINGATAN: Data nilai dan absensi siswa ini juga akan terhapus permanen.`)) {
      deleteStudent(id);
      refresh();
    }
  };

  // Filter Logic
  const filteredStudents = students.filter(s => {
    const matchName = s.name.toLowerCase().includes(searchTerm.toLowerCase());
    const matchClass = filterClass ? s.classId === filterClass : true;
    return matchName && matchClass;
  });

  // Pagination Logic
  const totalPages = Math.ceil(filteredStudents.length / itemsPerPage);
  const currentData = filteredStudents.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);

  // --- Export Functions (PROFESSIONAL FORMAT) ---
  const handleExport = (type: 'excel' | 'word' | 'print') => {
    const className = filterClass ? classes.find(c => c.id === filterClass)?.name : 'Semua Kelas';
    const fileName = `Data_Siswa_${className.replace(/\s+/g, '_')}`;
