    });

    // 2. Generate Full HTML Document
    const contentHTML = `
        <html>
        <head>
            <meta charset="UTF-8">
            <style>
                body { font-family: 'Times New Roman', serif; color: #000; }
                table { width: 100%; border-collapse: collapse; margin-top: 10px; }
