                        <li><button className="dropdown-item" onClick={() => handleExport('word')}>📄 Export Word (Rapi)</button></li>
                        <li><button className="dropdown-item" onClick={() => handleExport('print')}>🖨️ Print / PDF</button></li>
                    </ul>
                </div>
            )}
        </div>
      </div>

      {selectedClass && (
        <div className="card shadow-sm border-0">
          <div className="card-body p-0">
             {/* Legend */}
             <div className="p-3 border-bottom bg-light d-flex gap-3 flex-wrap">
                <span className="fw-bold">Keterangan:</span>
                <span className="badge bg-att-H text-dark border">H = Hadir</span>
                <span className="badge bg-att-I text-dark border">I = Izin</span>
                <span className="badge bg-att-S text-dark border">S = Sakit</span>
                <span className="badge bg-att-A text-dark border">A = Alfa</span>
             </div>

            <div className="table-responsive" style={{maxHeight: '75vh'}}>
