                <td style="text-align:center; font-weight:bold; background-color:#f0f0f0;">${row.sas.toFixed(0)}</td>
                <td style="text-align:center; font-weight:bold;">${row.final.toFixed(0)}</td>
                <td style="text-align:center; font-weight:bold;">${row.letter.letter}</td>
                <td style="text-align:center;">${row.rank}</td>
            </tr>
        `;
    });

    const contentHTML = `
        <html>
        <head>
            <meta charset="UTF-8">
            <style>
                body { font-family: 'Times New Roman', serif; color: #000; }
                table { width: 100%; border-collapse: collapse; margin-top: 10px; table-layout: fixed; }
                th, td { border: 1px solid #000; padding: 2px; font-size: 9pt; }
