                <p>REKAP NILAI KURIKULUM MERDEKA - BAHASA ARAB</p>
                <hr style="border: 2px double #000;">
            </div>

            <p><strong>Kelas:</strong> ${className} &nbsp;&nbsp;&nbsp; <strong>KKM:</strong> ${KKM}</p>

            <table>
                <thead>
                    <tr>
                        <th rowspan="2" width="20">No</th>
                        <th rowspan="2" width="150">Nama Siswa</th>
                        <th colspan="8">Formatif</th>
                        <th rowspan="2" width="30">Rata F</th>
                        <th colspan="5">Sumatif</th>
                        <th rowspan="2" width="30">Rata S</th>
                        <th colspan="3">SAS</th>
                        <th colspan="3">Hasil Akhir</th>
                    </tr>
                    <tr>
                        ${[1,2,3,4,5,6,7,8].map(i => `<th width="20">F${i}</th>`).join('')}
                        ${[1,2,3,4,5].map(i => `<th width="20">S${i}</th>`).join('')}
                        <th width="30">Non</th><th width="30">Tes</th><th width="30">NA</th>
                        <th width="30">Nilai</th><th width="25">Huruf</th><th width="25">Rank</th>
                    </tr>
                </thead>
                <tbody>${tableRows}</tbody>
            </table>

            <table class="signature">
                <tr>
                    <td width="70%"></td>
                    <td>
                        Bulukumba, ${dateStr}<br>
                        Guru Mata Pelajaran,<br><br><br><br>
                        <b><u>(Nama Guru Anda)</u></b><br>
                        NIP. -
                    </td>
                </tr>
            </table>
        </body>
        </html>
    `;

    if (type === 'print') {
        const iframe = document.createElement('iframe');
        iframe.style.display = 'none';
        document.body.appendChild(iframe);
        const doc = iframe.contentWindow?.document;
        if (doc) {
            doc.open();
            doc.write(contentHTML);
            doc.close();
            iframe.contentWindow?.focus();
            iframe.contentWindow?.print();
        }
        setTimeout(() => document.body.removeChild(iframe), 1000);
        return;
    }

    let mimeType = type === 'excel' ? 'application/vnd.ms-excel' : 'application/msword';
    let extension = type === 'excel' ? 'xls' : 'doc';

    const blob = new Blob([contentHTML], { type: mimeType });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${fileName}.${extension}`;
    a.click();
  };

  if (!classes.length) return <div className="alert alert-warning">Belum ada kelas. Silakan tambah kelas dulu.</div>;

  return (
    <div>
      <div className="d-flex justify-content-between align-items-center mb-4 no-print">
        <h2 className="text-dark">Rekap Nilai Kurikulum Merdeka</h2>
