```php
// StudentController.php

public function bulkImport(Request $request) {
    // Validasi input JSON
    $request->validate([
        'kelas_id' => 'required|exists:kelas,id',
        'students' => 'required|array'
    ]);

    $kelasId = $request->input('kelas_id');
    $students = $request->input('students'); // Array of names

    DB::transaction(function () use ($kelasId, $students) {
        foreach ($students as $name) {
             $siswa = Siswa::firstOrCreate([
                 'nama' => $name,
                 'kelas_id' => $kelasId
             ]);

             // Init Nilai & Kehadiran
             Nilai::firstOrCreate(['siswa_id' => $siswa->id]);
             Kehadiran::firstOrCreate(['siswa_id' => $siswa->id]);
        }
    });

    return response()->json(['message' => 'Import berhasil', 'count' => count($students)]);
}
```

