                <p>Kelas: ${className}</p>
            </div>

            <table>
                <thead>
                    <tr>
                        <th width="5%">NO</th>
                        <th width="20%">NISN</th>
                        <th width="45%">NAMA LENGKAP</th>
                        <th width="10%">L/P</th>
                        <th width="20%">KELAS</th>
                    </tr>
                </thead>
                <tbody>${tableRows}</tbody>
            </table>

            <div class="signature-section">
