      {!selectedClass ? (
         <div className="alert alert-info text-center py-5">
            Silakan pilih kelas terlebih dahulu untuk mulai menginput nilai.
         </div>
      ) : (
         <>
         {/* Stats Summary */}
         {stats && (
            <div className="row g-3 mb-4 no-print">
               <div className="col-md-3">
                 <div className="card bg-success text-white">
                    <div className="card-body py-3">
                        <small className="opacity-75">Nilai Tertinggi</small>
                        <h4 className="fw-bold mb-0">{stats.max.toFixed(0)}</h4>
                    </div>
                 </div>
               </div>
               <div className="col-md-3">
                 <div className="card bg-danger text-white">
                    <div className="card-body py-3">
                        <small className="opacity-75">Nilai Terendah</small>
                        <h4 className="fw-bold mb-0">{stats.min.toFixed(0)}</h4>
                    </div>
                 </div>
               </div>
               <div className="col-md-3">
                 <div className="card bg-primary text-white">
                    <div className="card-body py-3">
                        <small className="opacity-75">Rata-rata Kelas</small>
                        <h4 className="fw-bold mb-0">{stats.avg.toFixed(1)}</h4>
                    </div>
                 </div>
               </div>
               <div className="col-md-3">
                 <div className="card bg-light border">
                    <div className="card-body py-3">
                        <small className="text-muted">Ketuntasan</small>
                        <div className="d-flex justify-content-between align-items-end">
                            <span className="text-success fw-bold">{stats.tuntas} Tuntas</span>
                            <span className="text-danger fw-bold">{stats.belum} Belum</span>
                        </div>
                    </div>
                 </div>
               </div>
            </div>
         )}

         {/* Grading Table */}
         <div className="card shadow-sm border-0">
           <div className="card-body p-0">
             <div className="table-responsive" style={{maxHeight: '75vh'}}>
                <table className="table table-bordered mb-0 align-middle text-center table-sm table-hover" style={{fontSize: '0.85rem'}}>
                    <thead className="table-success text-dark align-middle sticky-header">
                        <tr>
                            <th rowSpan={2} className="sticky-col sticky-header-col p-3" style={{minWidth: '200px'}}>NAMA SISWA</th>
                            <th colSpan={8} className="sticky-header">FORMATIF (40%)</th>
                            <th colSpan={5} className="sticky-header">SUMATIF (30%)</th>
                            <th colSpan={3} className="sticky-header">SAS (30%)</th>
                            <th rowSpan={2} className="bg-dark text-white sticky-header" style={{width: '60px'}}>RAPOR</th>
                            <th rowSpan={2} className="sticky-header">KET</th>
                            <th rowSpan={2} className="sticky-header">RANK</th>
                        </tr>
                        <tr>
                            {/* F1-F8 */}
                            {Array.from({length:8}, (_, i) => <th key={i} className="sticky-header bg-white">F{i+1}</th>)}
                            {/* S1-S5 */}
                            {Array.from({length:5}, (_, i) => <th key={i} className="sticky-header bg-white">S{i+1}</th>)}

                            <th className="sticky-header bg-white">Non</th>
                            <th className="sticky-header bg-white">Tes</th>
                            <th className="sticky-header bg-white">NA</th>
                        </tr>
                    </thead>
                    <tbody>
                        {calculatedData.map((row, idx) => (
                            <tr key={row.id}>
                                <td className="text-start ps-3 fw-bold sticky-col bg-white">
                                    {row.name}
                                </td>

                                {/* Formatif Inputs */}
                                {row.g.formatif.map((val, i) => (
                                    <td key={`f-${i}`} className="p-0">
                                        <input 
                                            type="text" 
                                            className="form-control border-0 text-center shadow-none p-1"
                                            value={val === 0 ? '' : val}
                                            onChange={(e) => handleGradeChange(row.id, 'formatif', i, e.target.value)}
                                            style={{fontSize: '0.85rem', minWidth: '35px'}}
                                        />
                                    </td>
                                ))}

                                {/* Sumatif Inputs */}
                                {row.g.sumatif.map((val, i) => (
                                    <td key={`s-${i}`} className="p-0">
                                        <input 
                                            type="text" 
                                            className="form-control border-0 text-center shadow-none p-1 bg-light"
                                            value={val === 0 ? '' : val}
                                            onChange={(e) => handleGradeChange(row.id, 'sumatif', i, e.target.value)}
                                            style={{fontSize: '0.85rem', minWidth: '35px'}}
                                        />
                                    </td>
                                ))}

                                {/* SAS Inputs */}
                                <td className="p-0">
                                     <input type="text" className="form-control border-0 text-center shadow-none p-1" value={row.g.sasNonTes || ''} onChange={(e) => handleSasChange(row.id, 'sasNonTes', e.target.value)} />
                                </td>
                                <td className="p-0">
                                     <input type="text" className="form-control border-0 text-center shadow-none p-1" value={row.g.sasTes || ''} onChange={(e) => handleSasChange(row.id, 'sasTes', e.target.value)} />
                                </td>
                                <td className="bg-light fw-bold text-muted">{row.sas.toFixed(0)}</td>

                                {/* Final Result */}
                                <td className="bg-dark text-white fw-bold h5 mb-0 py-2">
                                    {row.final.toFixed(0)}
                                </td>
                                <td>
                                    <span className={`badge ${row.letter.color}`}>{row.letter.letter}</span>
                                </td>
                                <td className="fw-bold text-primary">#{row.rank}</td>
                            </tr>
                        ))}
                    </tbody>
                </table>
             </div>
           </div>
         </div>
         </>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Classroom, Student, AttendanceData } from '../types';
import { getClasses, getStudentsByClass, getAttendanceByStudent, saveAttendance, getUserProfile } from '../services/storageService';
import { ATTENDANCE_OPTIONS, TOTAL_MEETINGS, SCHOOL_NAME } from '../constants';

export const AttendanceSheet: React.FC = () => {
  const [selectedClass, setSelectedClass] = useState<string>('');
  const [classes, setClasses] = useState<Classroom[]>([]);
  const [students, setStudents] = useState<Student[]>([]);
  const [attendance, setAttendance] = useState<Record<string, AttendanceData>>({});

  useEffect(() => {
    setClasses(getClasses());
  }, []);

  useEffect(() => {
    if (selectedClass) {
      const clsStudents = getStudentsByClass(selectedClass);
      setStudents(clsStudents);
      const attMap: Record<string, AttendanceData> = {};
      clsStudents.forEach(s => {
        attMap[s.id] = getAttendanceByStudent(s.id);
      });
      setAttendance(attMap);
    }
  }, [selectedClass]);

  const handleStatusChange = (studentId: string, meetingIndex: number, status: string) => {
    const current = { ...attendance[studentId] };
    const newMeetings = [...current.meetings];
    newMeetings[meetingIndex] = status;
    current.meetings = newMeetings;

    setAttendance(prev => ({ ...prev, [studentId]: current }));
    saveAttendance(current);
  };

  const countStatus = (meetings: string[], status: string) => meetings.filter(m => m === status).length;

  const getStatusClass = (status: string) => {
    switch (status) {
      case 'H': return 'bg-att-H';
      case 'I': return 'bg-att-I';
      case 'S': return 'bg-att-S';
      case 'A': return 'bg-att-A';
      default: return 'bg-white';
    }
  };

  // --- Export Functions (PROFESSIONAL FORMAT) ---
  const handleExport = (type: 'excel' | 'word' | 'print') => {
    if (!selectedClass) return;
    const userProfile = getUserProfile();
    const className = classes.find(c => c.id === selectedClass)?.name || 'Kelas';
    const dateStr = new Date().toLocaleDateString('id-ID', {day: 'numeric', month: 'long', year: 'numeric'});
    const fileName = `Absensi_${className.replace(/\s+/g, '_')}`;

    // 1. Generate Table Header for Meetings
    let meetingHeaders = '';
    for (let i = 1; i <= TOTAL_MEETINGS; i++) {
        meetingHeaders += `<th width="20" style="text-align:center; font-size:8pt;">${i}</th>`;
    }

    // 2. Generate Rows
    let tableRows = '';
    students.forEach((s, idx) => {
        const att = attendance[s.id];
        let meetingCells = '';
        if (att) {
            att.meetings.forEach(m => {
                meetingCells += `<td style="text-align:center; font-size:9pt;">${m || '-'}</td>`;
            });
            const h = countStatus(att.meetings, 'H');
            const i = countStatus(att.meetings, 'I');
            const sakit = countStatus(att.meetings, 'S');
            const a = countStatus(att.meetings, 'A');

            tableRows += `
                <tr>
                    <td style="text-align:center;">${idx + 1}</td>
                    <td style="text-align:left; white-space:nowrap;">${s.name}</td>
                    ${meetingCells}
                    <td style="text-align:center; font-weight:bold;">${h}</td>
                    <td style="text-align:center;">${i}</td>
                    <td style="text-align:center;">${sakit}</td>
                    <td style="text-align:center; color:red;">${a}</td>
                </tr>
            `;
        }
    });

    // 3. Generate Content
    const contentHTML = `
        <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
        <head>
            <meta charset="UTF-8">
            <title>${fileName}</title>
            <style>
                @page { size: A4 landscape; margin: 1cm; }
                body { font-family: 'Times New Roman', serif; font-size: 11pt; color: #000; }
                .header { text-align: center; margin-bottom: 20px; }
                .header h3 { margin: 0; font-size: 14pt; font-weight: normal; text-transform: uppercase; }
                .header h2 { margin: 0; font-size: 16pt; font-weight: bold; text-transform: uppercase; }
                .header p { margin: 0; font-size: 11pt; font-style: italic; }
                .line { border-bottom: 3px double #000; margin-top: 5px; margin-bottom: 20px; }

                table { width: 100%; border-collapse: collapse; border-spacing: 0; margin-bottom: 20px; font-size: 9pt; table-layout: fixed; }
                th, td { border: 1px solid #000; padding: 2px; }
                th { background-color: #f2f2f2; font-weight: bold; text-align: center; vertical-align: middle; }

                .signature-section { margin-top: 30px; width: 100%; page-break-inside: avoid; }
                .signature-table { width: 100%; border: none; }
                .signature-table td { border: none; text-align: center; vertical-align: top; padding: 0; }
            </style>
        </head>
        <body>
            <div class="header">
                <h3>KEMENTERIAN AGAMA REPUBLIK INDONESIA</h3>
                <h2>${SCHOOL_NAME.toUpperCase()}</h2>
                <p>Alamat: Jl. Pendidikan No. 123, Kab. Bulukumba, Sulawesi Selatan</p>
                <div class="line"></div>
                <h3 style="font-weight: bold; text-decoration: underline; font-size: 12pt; margin-top: 10px;">REKAP ABSENSI SISWA</h3>
                <p>Kelas: ${className} | Tahun Pelajaran 2024/2025</p>
            </div>

            <table>
                <thead>
                    <tr>
                        <th rowspan="2" width="3%">No</th>
                        <th rowspan="2" width="15%">Nama Siswa</th>
                        <th colspan="${TOTAL_MEETINGS}">Pertemuan Ke-</th>
                        <th colspan="4">Rekapitulasi</th>
                    </tr>
                    <tr>
                        ${meetingHeaders}
                        <th width="3%">H</th><th width="3%">I</th><th width="3%">S</th><th width="3%">A</th>
                    </tr>
                </thead>
                <tbody>${tableRows}</tbody>
            </table>

            <div style="margin-bottom: 20px; font-size: 10pt;">
                <strong>Keterangan:</strong> H = Hadir, I = Izin, S = Sakit, A = Alfa
            </div>

            <div class="signature-section">
                <table class="signature-table">
                    <tr>
                        <td width="70%"></td>
                        <td width="30%">
                            Bulukumba, ${dateStr}<br>
                            Guru Mata Pelajaran,<br>
                            <br><br><br><br>
                            <strong><u>${userProfile.name}</u></strong><br>
                            NIP. ${userProfile.nip || '-'}
                        </td>
                    </tr>
                </table>
            </div>
        </body>
        </html>
    `;

    if (type === 'print') {
        const iframe = document.createElement('iframe');
        iframe.style.display = 'none';
        document.body.appendChild(iframe);
        const doc = iframe.contentWindow?.document;
        if (doc) {
            doc.open();
            doc.write(contentHTML);
            doc.close();
            iframe.contentWindow?.focus();
            iframe.contentWindow?.print();
        }
        setTimeout(() => document.body.removeChild(iframe), 1000);
        return;
    }

    let mimeType = type === 'excel' ? 'application/vnd.ms-excel' : 'application/msword';
    let extension = type === 'excel' ? 'xls' : 'doc';

    const blob = new Blob([contentHTML], { type: mimeType });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${fileName}.${extension}`;
    a.click();
  };

  return (
    <div>
      <div className="d-flex justify-content-between align-items-center mb-4 no-print">
        <h2 className="text-dark">Absensi Siswa</h2>
        <div className="d-flex gap-2">
            <select 
                className="form-select"
                value={selectedClass}
                onChange={(e) => setSelectedClass(e.target.value)}
            >
                <option value="">-- Pilih Kelas --</option>
                {classes.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>

            {selectedClass && (
                <div className="dropdown">
                    <button className="btn btn-primary dropdown-toggle" type="button" data-bs-toggle="dropdown">
                        📥 Backup Data
                    </button>
                    <ul className="dropdown-menu">
                        <li><button className="dropdown-item" onClick={() => handleExport('excel')}>📊 Export Excel (Rapi)</button></li>
                        <li><button className="dropdown-item" onClick={() => handleExport('word')}>📄 Export Word (Rapi)</button></li>
                        <li><button className="dropdown-item" onClick={() => handleExport('print')}>🖨️ Print / PDF</button></li>
                    </ul>
                </div>
            )}
        </div>
      </div>

      {selectedClass && (
        <div className="card shadow-sm border-0">
          <div className="card-body p-0">
             {/* Legend */}
             <div className="p-3 border-bottom bg-light d-flex gap-3 flex-wrap">
                <span className="fw-bold">Keterangan:</span>
                <span className="badge bg-att-H text-dark border">H = Hadir</span>
                <span className="badge bg-att-I text-dark border">I = Izin</span>
                <span className="badge bg-att-S text-dark border">S = Sakit</span>
                <span className="badge bg-att-A text-dark border">A = Alfa</span>
             </div>

            <div className="table-responsive" style={{maxHeight: '75vh'}}>
                <table id="attendance-table" className="table table-bordered mb-0 align-middle text-center" style={{fontSize: '0.9rem'}}>
                    <thead className="table-light sticky-header">
                    <tr>
                        <th rowSpan={2} className="align-middle sticky-col sticky-header-col p-3" style={{minWidth: '250px', left: 0}}>
                            NAMA SISWA (A-Z)
                        </th>
                        <th colSpan={TOTAL_MEETINGS} className="text-center py-2 bg-light sticky-header">Pertemuan Ke-</th>
                        <th colSpan={4} className="text-center bg-light sticky-header">Total</th>
                    </tr>
                    <tr>
                        {Array.from({ length: TOTAL_MEETINGS }).map((_, i) => (
                        <th key={i} className="small text-muted sticky-header bg-white" style={{minWidth: '60px'}}>{i + 1}</th>
                        ))}
                        <th className="bg-success text-white sticky-header">H</th>
                        <th className="bg-warning text-dark sticky-header">I</th>
                        <th className="bg-info text-white sticky-header">S</th>
                        <th className="bg-danger text-white sticky-header">A</th>
                    </tr>
                    </thead>
                    <tbody>
                    {students.map(s => {
                        const att = attendance[s.id];
                        if (!att) return null;
                        return (
                        <tr key={s.id}>
                            <td className="sticky-col text-start fw-bold px-3 py-2 bg-white">{s.name}</td>
                            {Array.from({ length: TOTAL_MEETINGS }).map((_, i) => (
                            <td key={i} className="p-0">
                                <select 
                                    className={`form-select border-0 shadow-none att-select ${getStatusClass(att.meetings[i])}`}
                                    value={att.meetings[i] || ''}
                                    onChange={(e) => handleStatusChange(s.id, i, e.target.value)}
                                >
                                    <option value="">-</option>
                                    {ATTENDANCE_OPTIONS.map(opt => <option key={opt} value={opt}>{opt}</option>)}
                                </select>
                            </td>
                            ))}
                            <td className="fw-bold">{countStatus(att.meetings, 'H')}</td>
                            <td>{countStatus(att.meetings, 'I')}</td>
                            <td>{countStatus(att.meetings, 'S')}</td>
                            <td className="fw-bold text-danger">{countStatus(att.meetings, 'A')}</td>
                        </tr>
                        );
                    })}
                    </tbody>
                </table>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { JournalEntry, Classroom } from '../types';
import { getClasses, getJournals, saveJournal, getUserProfile } from '../services/storageService';
import { SCHOOL_NAME } from '../constants';

export const JournalManager: React.FC = () => {
  const [entries, setEntries] = useState<JournalEntry[]>([]);
  const [classes, setClasses] = useState<Classroom[]>([]);
  const [showForm, setShowForm] = useState(false);
  const [form, setForm] = useState<Partial<JournalEntry>>({
    date: new Date().toISOString().split('T')[0],
    attendanceSummary: { hadir: 0, izin: 0, sakit: 0, alfa: 0 }
  });

  useEffect(() => {
    setClasses(getClasses());
    setEntries(getJournals().sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
  }, []);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.topic || !form.classId) return;

    const entry: JournalEntry = {
      id: Date.now().toString(),
      date: form.date!,
      classId: form.classId!,
      topic: form.topic!,
      activity: form.activity || '',
      notes: form.notes || '',
      attendanceSummary: {
        hadir: Number(form.attendanceSummary?.hadir) || 0,
        izin: Number(form.attendanceSummary?.izin) || 0,
        sakit: Number(form.attendanceSummary?.sakit) || 0,
        alfa: Number(form.attendanceSummary?.alfa) || 0,
      }
    };

    saveJournal(entry);
    setEntries([entry, ...entries].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
    setShowForm(false);
    setForm({ date: new Date().toISOString().split('T')[0], attendanceSummary: { hadir: 0, izin: 0, sakit: 0, alfa: 0 } });
  };

  // --- Export Functions (PROFESSIONAL FORMAT) ---
  const handleExport = (type: 'excel' | 'word' | 'print') => {
    const userProfile = getUserProfile();
    const fileName = `Jurnal_Mengajar_${new Date().toISOString().split('T')[0]}`;
    const dateStr = new Date().toLocaleDateString('id-ID', {day: 'numeric', month: 'long', year: 'numeric'});

    let tableRows = '';
    entries.forEach((entry, idx) => {
        const className = classes.find(c => c.id === entry.classId)?.name || '-';
        const entryDate = new Date(entry.date).toLocaleDateString('id-ID');
        tableRows += `
            <tr>
                <td style="text-align:center;">${idx + 1}</td>
                <td style="text-align:center;">${entryDate}</td>
                <td style="text-align:center;">${className}</td>
                <td>${entry.topic}</td>
                <td>${entry.activity}</td>
                <td style="text-align:center; font-size: 10pt;">H:${entry.attendanceSummary.hadir}, I:${entry.attendanceSummary.izin}, S:${entry.attendanceSummary.sakit}, A:${entry.attendanceSummary.alfa}</td>
                <td>${entry.notes}</td>
            </tr>
        `;
    });

    const contentHTML = `
        <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
        <head>
            <meta charset="UTF-8">
            <title>${fileName}</title>
            <style>
                @page { size: A4 portrait; margin: 2cm; }
                body { font-family: 'Times New Roman', serif; font-size: 11pt; color: #000; }
                .header { text-align: center; margin-bottom: 20px; }
                .header h3 { margin: 0; font-size: 14pt; font-weight: normal; text-transform: uppercase; }
                .header h2 { margin: 0; font-size: 16pt; font-weight: bold; text-transform: uppercase; }
                .header p { margin: 0; font-size: 11pt; font-style: italic; }
                .line { border-bottom: 3px double #000; margin-top: 5px; margin-bottom: 20px; }

                table { width: 100%; border-collapse: collapse; border-spacing: 0; margin-bottom: 20px; font-size: 11pt; }
                th, td { border: 1px solid #000; padding: 5px; vertical-align: top; }
                th { background-color: #f2f2f2; font-weight: bold; text-align: center; }

                .signature-section { margin-top: 30px; width: 100%; page-break-inside: avoid; }
                .signature-table { width: 100%; border: none; }
                .signature-table td { border: none; text-align: center; vertical-align: top; padding: 0; }
            </style>
        </head>
        <body>
            <div class="header">
                <h3>KEMENTERIAN AGAMA REPUBLIK INDONESIA</h3>
                <h2>${SCHOOL_NAME.toUpperCase()}</h2>
                <p>Alamat: Jl. Pendidikan No. 123, Kab. Bulukumba, Sulawesi Selatan</p>
                <div class="line"></div>
                <h3 style="font-weight: bold; text-decoration: underline; font-size: 12pt; margin-top: 10px;">JURNAL MENGAJAR GURU</h3>
                <p>Mata Pelajaran: Bahasa Arab | Tahun Pelajaran 2024/2025</p>
            </div>

            <table>
                <thead>
                    <tr>
                        <th width="5%">No</th>
                        <th width="12%">Tanggal</th>
                        <th width="8%">Kelas</th>
                        <th width="20%">Materi / TP</th>
                        <th width="25%">Kegiatan Pembelajaran</th>
                        <th width="15%">Absensi</th>
                        <th width="15%">Catatan</th>
                    </tr>
                </thead>
                <tbody>${tableRows}</tbody>
            </table>

            <div class="signature-section">
                <table class="signature-table">
                    <tr>
                        <td width="50%">
                            Mengetahui,<br>
                            Kepala Madrasah,<br><br><br><br>
                            <b><u>( ........................... )</u></b><br>
                            NIP. ...........................
                        </td>
                        <td width="50%">
                            Bulukumba, ${dateStr}<br>
                            Guru Mata Pelajaran,<br><br><br><br>
                            <strong><u>${userProfile.name}</u></strong><br>
                            NIP. ${userProfile.nip || '-'}
                        </td>
                    </tr>
                </table>
            </div>
        </body>
        </html>
    `;

    if (type === 'print') {
        const iframe = document.createElement('iframe');
        iframe.style.display = 'none';
        document.body.appendChild(iframe);
        const doc = iframe.contentWindow?.document;
        if (doc) {
            doc.open();
            doc.write(contentHTML);
            doc.close();
            iframe.contentWindow?.focus();
            iframe.contentWindow?.print();
        }
        setTimeout(() => document.body.removeChild(iframe), 1000);
        return;
    }

    let mimeType = type === 'excel' ? 'application/vnd.ms-excel' : 'application/msword';
    let extension = type === 'excel' ? 'xls' : 'doc';

    const blob = new Blob([contentHTML], { type: mimeType });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${fileName}.${extension}`;
    a.click();
  };

  return (
    <div>
      <div className="d-flex justify-content-between align-items-center mb-4 no-print">
        <h2 className="text-dark">Jurnal Mengajar Harian</h2>
        <div className="d-flex gap-2">
            <button onClick={() => setShowForm(!showForm)} className={`btn ${showForm ? 'btn-secondary' : 'btn-success'}`}>
                {showForm ? 'Batal' : '+ Tulis Jurnal'}
            </button>
            <div className="dropdown">
                <button className="btn btn-primary dropdown-toggle" type="button" data-bs-toggle="dropdown">
                    📥 Backup Data
                </button>
                <ul className="dropdown-menu">
                    <li><button className="dropdown-item" onClick={() => handleExport('excel')}>📊 Export Excel (Rapi)</button></li>
                    <li><button className="dropdown-item" onClick={() => handleExport('word')}>📄 Export Word (Rapi)</button></li>
                    <li><button className="dropdown-item" onClick={() => handleExport('print')}>🖨️ Print / PDF</button></li>
                </ul>
            </div>
        </div>
      </div>

      {showForm && (
        <div className="card shadow mb-4 border-top border-success border-4 no-print">
          <div className="card-body">
            <h5 className="text-center fw-bold mb-3">{SCHOOL_NAME} - Form Jurnal</h5>
            <form onSubmit={handleSubmit}>
                <div className="row g-3">
                    <div className="col-md-6">
                        <label className="form-label">Tanggal</label>
                        <input type="date" className="form-control" value={form.date} onChange={e => setForm({...form, date: e.target.value})} required />
                    </div>
                    <div className="col-md-6">
                        <label className="form-label">Kelas</label>
                        <select className="form-select" value={form.classId} onChange={e => setForm({...form, classId: e.target.value})} required>
                            <option value="">Pilih Kelas</option>
                            {classes.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                        </select>
                    </div>
                    <div className="col-12">
                        <label className="form-label">Materi / TP</label>
                        <input type="text" className="form-control" value={form.topic} onChange={e => setForm({...form, topic: e.target.value})} required />
                    </div>
                    <div className="col-12">
                        <label className="form-label">Kegiatan Pembelajaran</label>
                        <textarea className="form-control" rows={3} value={form.activity} onChange={e => setForm({...form, activity: e.target.value})} />
                    </div>
                    <div className="col-12">
                        <label className="form-label mb-1">Rekap Absensi (Jumlah Siswa)</label>
                        <div className="row g-2">
                            <div className="col">
                                <input type="number" placeholder="Hadir" className="form-control text-center border-success" value={form.attendanceSummary?.hadir} onChange={e => setForm({...form, attendanceSummary: {...form.attendanceSummary!, hadir: parseInt(e.target.value)}})} />
                            </div>
                            <div className="col">
                                <input type="number" placeholder="Izin" className="form-control text-center border-info" value={form.attendanceSummary?.izin} onChange={e => setForm({...form, attendanceSummary: {...form.attendanceSummary!, izin: parseInt(e.target.value)}})} />
                            </div>
                            <div className="col">
                                <input type="number" placeholder="Sakit" className="form-control text-center border-warning" value={form.attendanceSummary?.sakit} onChange={e => setForm({...form, attendanceSummary: {...form.attendanceSummary!, sakit: parseInt(e.target.value)}})} />
                            </div>
                            <div className="col">
                                <input type="number" placeholder="Alfa" className="form-control text-center border-danger" value={form.attendanceSummary?.alfa} onChange={e => setForm({...form, attendanceSummary: {...form.attendanceSummary!, alfa: parseInt(e.target.value)}})} />
                            </div>
                        </div>
                    </div>
                    <div className="col-12">
                        <label className="form-label">Catatan Khusus</label>
                        <textarea className="form-control" value={form.notes} onChange={e => setForm({...form, notes: e.target.value})} />
                    </div>
                    <div className="col-12">
                        <button type="submit" className="btn btn-success w-100">Simpan Jurnal</button>
                    </div>
                </div>
            </form>
          </div>
        </div>
      )}

      <div className="row g-3">
        {entries.length === 0 ? (
            <div className="text-center py-5 text-muted">
                Belum ada data jurnal. Silakan buat jurnal baru.
            </div>
        ) : (
            entries.map(entry => (
            <div key={entry.id} className="col-12">
                <div className="card shadow-sm h-100 hover-shadow break-inside-avoid">
                    <div className="card-body">
                        <div className="d-flex justify-content-between align-items-start border-bottom pb-2 mb-2">
                            <div>
                                <h5 className="fw-bold text-success mb-1">{entry.topic}</h5>
                                <small className="text-muted">
                                    {new Date(entry.date).toLocaleDateString('id-ID', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })} • 
                                    Kelas: {classes.find(c => c.id === entry.classId)?.name || '?'}
                                </small>
                            </div>
                        </div>
                        <p className="card-text text-dark mb-3" style={{whiteSpace: 'pre-line'}}>
                            <strong>Kegiatan:</strong> {entry.activity}
                        </p>
                        <div className="bg-light p-2 rounded d-flex gap-3 small mb-2">
                            <span className="fw-bold text-success">✅ H: {entry.attendanceSummary.hadir}</span>
                            <span className="fw-bold text-info">ℹ️ I: {entry.attendanceSummary.izin}</span>
                            <span className="fw-bold text-warning">🏥 S: {entry.attendanceSummary.sakit}</span>
                            <span className="fw-bold text-danger">❌ A: {entry.attendanceSummary.alfa}</span>
                        </div>
                        {entry.notes && (
                            <div className="alert alert-warning py-1 px-2 small mb-0 fst-italic">
                                Note: {entry.notes}
                            </div>
                        )}
                    </div>
                </div>
            </div>
            ))
        )}
      </div>
    </div>
  );
};
